/* CISM :: content/quiz2.js — CISM Domain 2 question bank (100 items). */
window.CISM = window.CISM || {}; CISM.questions = CISM.questions || [];
CISM.questions.push.apply(CISM.questions, [
{"id":"D2-001","domain":2,"obj":"2A1","diff":"easy","q":"An information security manager is building the organization's first formal risk management program. Which activity should be performed FIRST?","options":["Select a risk treatment for each identified vulnerability","Establish the scope and boundaries of the risk management process","Purchase cyber-insurance to transfer residual risk","Deploy a security information and event management (SIEM) tool"],"answer":1,"explain":"<strong>Establish the scope and boundaries of the risk management process</strong> — defining what assets, business units, and processes are in scope is the foundation that every later risk identification, analysis, and treatment activity depends on.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Select a risk treatment for each identified vulnerability</b>: treatment decisions cannot be made before risks are identified within a defined scope.</span><span class='qd'><b>Purchase cyber-insurance to transfer residual risk</b>: transfer is a treatment option chosen after risk analysis, not a starting point.</span><span class='qd'><b>Deploy a security information and event management (SIEM) tool</b>: a monitoring control is selected after risks and requirements are understood.</span>"},
{"id":"D2-002","domain":2,"obj":"2A1","diff":"med","q":"Which of the following BEST describes the primary purpose of a risk register?","options":["To list all technical vulnerabilities found during penetration testing","To document the results of the most recent compliance audit","To track help desk tickets related to security incidents","To provide a centralized, living record of identified risks, their analysis, and treatment status"],"answer":3,"explain":"<strong>To provide a centralized, living record of identified risks, their analysis, and treatment status</strong> — the risk register is the authoritative repository that tracks each risk from identification through analysis, treatment decision, ownership, and ongoing status.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To list all technical vulnerabilities found during penetration testing</b>: a vulnerability list is only one input to risk identification, not the register itself.</span><span class='qd'><b>To document the results of the most recent compliance audit</b>: audit findings are a separate output that may feed the register but do not define it.</span><span class='qd'><b>To track help desk tickets related to security incidents</b>: incident tickets belong to incident management, not enterprise risk tracking.</span>"},
{"id":"D2-003","domain":2,"obj":"2B2","diff":"hard","q":"An asset has an asset value (AV) of $500,000 and an exposure factor (EF) of 40% for a specific threat. What is the single loss expectancy (SLE)?","options":["$200,000","$50,000","$125,000","$500,000"],"answer":0,"explain":"<strong>$200,000</strong> — SLE = AV x EF = $500,000 x 0.40 = $200,000.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>$50,000</b>: results from an incorrect exposure factor (10%) rather than the given 40%.</span><span class='qd'><b>$125,000</b>: does not correspond to any correct multiplication of the given AV and EF.</span><span class='qd'><b>$500,000</b>: this is the full asset value, ignoring the exposure factor entirely.</span>"},
{"id":"D2-004","domain":2,"obj":"2B2","diff":"med","q":"A risk has an SLE of $80,000 and an annualized rate of occurrence (ARO) of 0.25 (expected once every four years). What is the annualized loss expectancy (ALE)?","options":["$320,000","$20,000","$80,000","$4,000"],"answer":1,"explain":"<strong>$20,000</strong> — ALE = SLE x ARO = $80,000 x 0.25 = $20,000.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>$320,000</b>: results from dividing rather than multiplying (incorrectly treating ARO as a divisor).</span><span class='qd'><b>$80,000</b>: this is only the SLE, ignoring frequency of occurrence.</span><span class='qd'><b>$4,000</b>: results from a miscalculation using 0.05 instead of the given 0.25 ARO.</span>"},
{"id":"D2-005","domain":2,"obj":"2B2","diff":"easy","q":"A proposed control costs $30,000 annually and is expected to reduce ALE from $100,000 to $55,000. What is the return on security investment (ROSI)?","options":["50%","45%","83%","150%"],"answer":0,"explain":"<strong>50%</strong> — ROSI = (Risk reduction - Cost of control) / Cost of control = (($100,000 - $55,000) - $30,000) / $30,000 = $15,000 / $30,000 = 50%.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>45%</b>: does not match the risk-reduction-minus-cost-over-cost formula using the figures given.</span><span class='qd'><b>83%</b>: results from dividing the risk reduction by an incorrect base rather than the $30,000 control cost.</span><span class='qd'><b>150%</b>: represents the gross benefit-to-cost ratio ($45,000/$30,000) without properly forming the net ROSI ratio.</span>"},
{"id":"D2-006","domain":2,"obj":"2A2","diff":"hard","q":"Who is MOST appropriate to serve as the owner of a specific business risk?","options":["The information security manager","The senior manager accountable for the business process or asset affected by the risk","The internal audit director","The IT help desk supervisor"],"answer":1,"explain":"<strong>The senior manager accountable for the business process or asset affected by the risk</strong> — risk ownership belongs to the business role that has authority over the asset/process and accountability for outcomes, ensuring treatment decisions align with business priorities.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The information security manager</b>: typically owns security controls and facilitates the risk process but is not accountable for the business outcome.</span><span class='qd'><b>The internal audit director</b>: provides independent assurance and should not own risks it must objectively assess.</span><span class='qd'><b>The IT help desk supervisor</b>: operates at a tactical support level and lacks the authority to accept or treat business risk.</span>"},
{"id":"D2-007","domain":2,"obj":"2A2","diff":"med","q":"What is the KEY difference between a risk owner and a control owner?","options":["There is no meaningful difference; the terms are interchangeable","The control owner sets organizational risk appetite, while the risk owner implements technical safeguards","The risk owner is always in IT, while the control owner is always in the business","The risk owner is accountable for the risk outcome, while the control owner is responsible for operating and maintaining a specific control that treats the risk"],"answer":3,"explain":"<strong>The risk owner is accountable for the risk outcome, while the control owner is responsible for operating and maintaining a specific control that treats the risk</strong> — one risk may be treated by multiple controls with different control owners, but overall accountability for the risk remains with the risk owner.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>There is no meaningful difference; the terms are interchangeable</b>: conflating the roles removes accountability clarity, which defeats the purpose of assigning ownership.</span><span class='qd'><b>The control owner sets organizational risk appetite, while the risk owner implements technical safeguards</b>: this reverses the actual responsibilities of each role.</span><span class='qd'><b>The risk owner is always in IT, while the control owner is always in the business</b>: ownership is determined by accountability and function, not a fixed departmental rule.</span>"},
{"id":"D2-008","domain":2,"obj":"2A3","diff":"easy","q":"Which risk analysis approach relies on numerical values such as monetary loss and probability percentages?","options":["Quantitative risk analysis","Qualitative risk analysis","Delphi technique","Heat-map scoring only"],"answer":0,"explain":"<strong>Quantitative risk analysis</strong> — this approach expresses likelihood and impact in numerical/monetary terms (e.g., ALE, ROSI), enabling direct cost-benefit comparisons.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Qualitative risk analysis</b>: uses descriptive categories such as high/medium/low rather than precise numeric values.</span><span class='qd'><b>Delphi technique</b>: is a structured method for gathering expert consensus and can support either qualitative or quantitative analysis, but is not itself the numerical approach.</span><span class='qd'><b>Heat-map scoring only</b>: heat maps typically visualize qualitative or semi-quantitative scores, not precise monetary figures.</span>"},
{"id":"D2-009","domain":2,"obj":"2A3","diff":"med","q":"An organization with limited historical loss data and a need for a quick, broad risk assessment across many business units would MOST likely choose which analysis method?","options":["Pure quantitative analysis using Monte Carlo simulation","Actuarial analysis based on insurance industry loss tables","Qualitative analysis using expert judgment and descriptive risk ratings","Full statistical regression modeling of historical incidents"],"answer":2,"explain":"<strong>Qualitative analysis using expert judgment and descriptive risk ratings</strong> — when data is scarce and speed/breadth matter, qualitative methods let experts rate likelihood and impact quickly without requiring extensive historical loss data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Pure quantitative analysis using Monte Carlo simulation</b>: requires substantial data inputs and modeling effort that are impractical without historical data.</span><span class='qd'><b>Actuarial analysis based on insurance industry loss tables</b>: is specialized, resource-intensive, and not typically used for a broad internal rapid assessment.</span><span class='qd'><b>Full statistical regression modeling of historical incidents</b>: depends on rich historical data sets that are explicitly stated to be unavailable.</span>"},
{"id":"D2-010","domain":2,"obj":"2B3","diff":"hard","q":"A manufacturing company decides not to deploy an IoT-enabled predictive maintenance platform because the security risks of the emerging technology outweigh the operational benefits at this time. This is an example of which risk treatment?","options":["Risk mitigation","Risk avoidance","Risk transfer","Risk acceptance"],"answer":1,"explain":"<strong>Risk avoidance</strong> — choosing not to pursue the activity that introduces the risk (not deploying the platform) eliminates exposure to that specific risk entirely.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk mitigation</b>: would involve deploying the platform with compensating controls to reduce risk, not forgoing it.</span><span class='qd'><b>Risk transfer</b>: would shift financial impact to a third party, such as through insurance or contract terms, which is not described here.</span><span class='qd'><b>Risk acceptance</b>: would mean proceeding with the deployment and knowingly tolerating the residual risk, which contradicts the decision made.</span>"},
{"id":"D2-011","domain":2,"obj":"2B3","diff":"med","q":"Purchasing a cyber-liability insurance policy to cover the financial impact of a data breach is an example of which risk treatment strategy?","options":["Risk avoidance","Risk transfer","Risk mitigation","Risk acceptance"],"answer":1,"explain":"<strong>Risk transfer</strong> — insurance shifts the financial consequence of a loss event to a third party (the insurer) in exchange for a premium, without eliminating the underlying threat or vulnerability.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk avoidance</b>: would require eliminating the activity that creates the risk, not insuring against it.</span><span class='qd'><b>Risk mitigation</b>: would involve implementing controls that reduce the likelihood or impact directly, which insurance does not do.</span><span class='qd'><b>Risk acceptance</b>: would mean retaining the full financial impact without any offsetting mechanism.</span>"},
{"id":"D2-012","domain":2,"obj":"2B3","diff":"easy","q":"Senior management reviews a low-likelihood, low-impact risk and formally documents a decision to take no further action, retaining the risk within approved appetite. This is BEST described as which treatment option?","options":["Risk mitigation","Risk avoidance","Risk transfer","Risk acceptance"],"answer":3,"explain":"<strong>Risk acceptance</strong> — a documented, authorized decision to retain a risk without additional controls, made by someone with the authority to do so, is the definition of risk acceptance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk mitigation</b>: implies implementing controls to reduce the risk, which was not done here.</span><span class='qd'><b>Risk avoidance</b>: would require discontinuing the activity generating the risk, not retaining it.</span><span class='qd'><b>Risk transfer</b>: would involve shifting impact to a third party, which is not part of this scenario.</span>"},
{"id":"D2-013","domain":2,"obj":"2A4","diff":"med","q":"Which term BEST describes the amount of risk an organization is willing to accept in pursuit of its objectives, expressed at a strategic level?","options":["Risk tolerance","Inherent risk","Control risk","Risk appetite"],"answer":3,"explain":"<strong>Risk appetite</strong> — this is the high-level, strategic statement of how much risk the organization is willing to pursue or retain to achieve its objectives, typically set by the board or senior management.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk tolerance</b>: refers to the acceptable variation around specific objectives or metrics, operationalizing appetite at a more granular level.</span><span class='qd'><b>Inherent risk</b>: is the level of risk that exists before any controls are applied, unrelated to willingness to accept risk.</span><span class='qd'><b>Control risk</b>: is the risk that a control fails to prevent or detect an error or event, a different concept entirely.</span>"},
{"id":"D2-014","domain":2,"obj":"2A4","diff":"hard","q":"An organization's risk appetite statement allows for a maximum of 4 hours of unplanned downtime per critical system per quarter. This specific, measurable threshold is BEST described as an example of:","options":["Risk tolerance","Risk appetite","Residual risk","Inherent risk"],"answer":0,"explain":"<strong>Risk tolerance</strong> — tolerance is the specific, measurable acceptable deviation from an objective (such as an uptime target), operationalizing the broader risk appetite into actionable thresholds.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk appetite</b>: is the broader, strategic-level statement of overall willingness to accept risk, not the specific numeric threshold.</span><span class='qd'><b>Residual risk</b>: is the risk remaining after controls are applied, a different measurement altogether.</span><span class='qd'><b>Inherent risk</b>: is the risk level before controls are considered, unrelated to a tolerance threshold.</span>"},
{"id":"D2-015","domain":2,"obj":"2A1","diff":"easy","q":"During risk identification, an information security manager discovers a threat with no corresponding vulnerability in the organization's environment. What is the MOST accurate conclusion?","options":["The residual risk is high and must be immediately mitigated","There is effectively no exploitable risk from this threat at this time because no vulnerability exists for it to exploit","The threat should be added to the risk register as a critical risk regardless","Risk transfer is the only viable treatment"],"answer":1,"explain":"<strong>There is effectively no exploitable risk from this threat at this time because no vulnerability exists for it to exploit</strong> — risk requires both a threat and a corresponding vulnerability; without a vulnerability, the threat has no avenue to cause harm, though the situation should still be monitored as the environment changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The residual risk is high and must be immediately mitigated</b>: without a vulnerability there is nothing currently exploitable, so urgent mitigation is not warranted.</span><span class='qd'><b>The threat should be added to the risk register as a critical risk regardless</b>: logging every threat as critical without a vulnerability misrepresents actual exposure and dilutes register accuracy.</span><span class='qd'><b>Risk transfer is the only viable treatment</b>: treatment is unnecessary when there is no current exploitable risk.</span>"},
{"id":"D2-016","domain":2,"obj":"2A5","diff":"med","q":"Which of the following is the MOST important reason to integrate information security risk management with the organization's enterprise risk management (ERM) program?","options":["It ensures information security risk is considered alongside other business risks so resources are prioritized consistently across the enterprise","It reduces the total number of risks that must be tracked","It eliminates the need for a dedicated information security risk register","It automatically satisfies all regulatory reporting requirements"],"answer":0,"explain":"<strong>It ensures information security risk is considered alongside other business risks so resources are prioritized consistently across the enterprise</strong> — integration with ERM allows security risks to be evaluated using the same criteria and appetite as financial, operational, and strategic risks, enabling consistent, enterprise-wide prioritization.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It reduces the total number of risks that must be tracked</b>: integration changes how risks are reported and prioritized, not the underlying number of risks that exist.</span><span class='qd'><b>It eliminates the need for a dedicated information security risk register</b>: a detailed security-specific register is still needed to support the higher-level ERM view.</span><span class='qd'><b>It automatically satisfies all regulatory reporting requirements</b>: ERM integration supports but does not by itself guarantee compliance with every specific regulation.</span>"},
{"id":"D2-017","domain":2,"obj":"2A5","diff":"med","q":"An information security manager wants risk-based decisions to be made consistently across IT, finance, and operations. Which action BEST supports this goal?","options":["Allow each business unit to define its own risk rating scale independently","Adopt a common enterprise risk taxonomy and rating scale used by all business units, including information security","Require only the information security function to use quantitative analysis","Limit risk assessments to the IT department to reduce complexity"],"answer":1,"explain":"<strong>Adopt a common enterprise risk taxonomy and rating scale used by all business units, including information security</strong> — a shared taxonomy and scale ensures that risk ratings from different functions are comparable, enabling consistent enterprise-wide prioritization and resource allocation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Allow each business unit to define its own risk rating scale independently</b>: inconsistent scales make cross-functional comparison and prioritization impossible.</span><span class='qd'><b>Require only the information security function to use quantitative analysis</b>: singling out one function undermines comparability across the enterprise.</span><span class='qd'><b>Limit risk assessments to the IT department to reduce complexity</b>: excluding other business units ignores risks that originate outside IT and defeats the purpose of enterprise-wide risk management.</span>"},
{"id":"D2-018","domain":2,"obj":"2B1","diff":"hard","q":"Which of the following is the BEST definition of a key risk indicator (KRI)?","options":["A metric used to measure the historical financial performance of the security department","A list of all controls implemented across the organization","A summary of audit findings from the past fiscal year","A metric that provides early warning of increasing risk exposure in a specific area"],"answer":3,"explain":"<strong>A metric that provides early warning of increasing risk exposure in a specific area</strong> — KRIs are forward-looking or leading metrics designed to signal that risk levels are rising before a loss event occurs, enabling proactive response.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A metric used to measure the historical financial performance of the security department</b>: this describes a budget or performance metric, not a risk indicator.</span><span class='qd'><b>A list of all controls implemented across the organization</b>: this describes a control inventory, not a risk indicator.</span><span class='qd'><b>A summary of audit findings from the past fiscal year</b>: audit findings are a point-in-time assurance output, not an ongoing leading indicator.</span>"},
{"id":"D2-019","domain":2,"obj":"2B1","diff":"easy","q":"Which characteristic is MOST important for a metric to be effective as a key risk indicator?","options":["It must be reported only annually to the board","It must be easy to manipulate by the process owner","It must always be expressed in monetary terms","It must be measurable, relevant to a specific risk, and able to signal a change in risk level in time for action"],"answer":3,"explain":"<strong>It must be measurable, relevant to a specific risk, and able to signal a change in risk level in time for action</strong> — an effective KRI is quantifiable, tied to a meaningful risk, and timely enough that management can respond before the risk materializes into a loss.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It must be reported only annually to the board</b>: annual reporting is far too infrequent for a leading indicator meant to provide early warning.</span><span class='qd'><b>It must be easy to manipulate by the process owner</b>: a metric that can be easily manipulated undermines its reliability and integrity.</span><span class='qd'><b>It must always be expressed in monetary terms</b>: many effective KRIs, such as patch latency or failed login trends, are non-monetary yet highly effective.</span>"},
{"id":"D2-020","domain":2,"obj":"2B4","diff":"med","q":"An organization is evaluating a new cloud service provider that will process sensitive customer data. Which activity is MOST important before signing the contract?","options":["Confirming the provider offers the lowest price among competitors","Waiting until after go-live to review the provider's security posture","Performing a third-party risk assessment of the provider's security controls, certifications, and data handling practices","Delegating all risk decisions to the procurement department without security input"],"answer":2,"explain":"<strong>Performing a third-party risk assessment of the provider's security controls, certifications, and data handling practices</strong> — assessing the vendor's security posture, relevant certifications (e.g., SOC 2, ISO 27001), and data handling practices before contract signing ensures risks are understood and can be addressed contractually.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Confirming the provider offers the lowest price among competitors</b>: cost is a business factor but does not address the security and data protection risks of the engagement.</span><span class='qd'><b>Waiting until after go-live to review the provider's security posture</b>: reviewing after go-live is too late to negotiate protections or decline unacceptable risk.</span><span class='qd'><b>Delegating all risk decisions to the procurement department without security input</b>: procurement lacks the specialized expertise to evaluate technical and security risk adequately.</span>"},
{"id":"D2-021","domain":2,"obj":"2B4","diff":"easy","q":"During due diligence, a security manager finds that a critical third-party vendor lacks an independent audit report and refuses to allow an on-site assessment. What is the BEST next step?","options":["Proceed with the contract since the vendor is well known in the market","Require compensating contractual controls (e.g., right-to-audit clauses, security SLAs, breach notification terms) and escalate the residual risk to the risk owner for a formal decision","Cancel all future vendor relationships across the organization","Ignore the finding since third-party risk is the vendor's responsibility, not the organization's"],"answer":1,"explain":"<strong>Require compensating contractual controls (e.g., right-to-audit clauses, security SLAs, breach notification terms) and escalate the residual risk to the risk owner for a formal decision</strong> — when direct assurance is unavailable, contractual safeguards reduce exposure, and the remaining residual risk must be transparently escalated so an accountable owner can accept, reject, or further treat it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Proceed with the contract since the vendor is well known in the market</b>: reputation alone does not substitute for verified security assurance.</span><span class='qd'><b>Cancel all future vendor relationships across the organization</b>: an overly broad reaction is disproportionate to a single vendor's due diligence gap.</span><span class='qd'><b>Ignore the finding since third-party risk is the vendor's responsibility, not the organization's</b>: the organization remains accountable for risk introduced through its vendors, particularly involving its own data.</span>"},
{"id":"D2-022","domain":2,"obj":"2A3","diff":"med","q":"A security manager is choosing between a purely qualitative and a purely quantitative risk analysis approach for a new enterprise resource planning (ERP) implementation. Which factor would MOST justify using a quantitative approach?","options":["The organization has no historical loss or frequency data available","The assessment must be completed within one business day","Stakeholders prefer simple high/medium/low ratings for a board presentation","Management requires a precise dollar-based cost-benefit justification for a large capital investment in controls"],"answer":3,"explain":"<strong>Management requires a precise dollar-based cost-benefit justification for a large capital investment in controls</strong> — quantitative analysis is best suited when a specific monetary justification, such as calculating ALE and ROSI to support a capital expenditure decision, is required.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The organization has no historical loss or frequency data available</b>: lack of reliable data actually favors a qualitative approach, since quantitative analysis depends on solid data inputs.</span><span class='qd'><b>The assessment must be completed within one business day</b>: quantitative analysis is typically more time- and data-intensive, making qualitative analysis faster under tight deadlines.</span><span class='qd'><b>Stakeholders prefer simple high/medium/low ratings for a board presentation</b>: a preference for simple descriptive ratings points toward qualitative analysis, not quantitative.</span>"},
{"id":"D2-023","domain":2,"obj":"2B2","diff":"hard","q":"An asset worth $2,000,000 faces a threat with an exposure factor of 25%. The threat is expected to occur twice every 5 years. What is the ALE?","options":["$100,000","$500,000","$200,000","$250,000"],"answer":2,"explain":"<strong>$200,000</strong> — SLE = AV x EF = $2,000,000 x 0.25 = $500,000. ARO = 2/5 = 0.4. ALE = SLE x ARO = $500,000 x 0.4 = $200,000.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>$100,000</b>: results from using an incorrect ARO of 0.2 instead of the correct 0.4.</span><span class='qd'><b>$500,000</b>: this is the SLE value only, without applying the annualized rate of occurrence.</span><span class='qd'><b>$250,000</b>: does not correspond to the correct multiplication of SLE and ARO using the given figures.</span>"},
{"id":"D2-024","domain":2,"obj":"2A1","diff":"med","q":"Which of the following BEST distinguishes a threat from a vulnerability?","options":["A threat is a potential cause of an unwanted event, while a vulnerability is a weakness that could be exploited by that threat","A threat is a weakness that can be exploited, while a vulnerability is the entity that exploits it","There is no practical distinction between the two terms","A vulnerability always results in a loss, while a threat never does"],"answer":0,"explain":"<strong>A threat is a potential cause of an unwanted event, while a vulnerability is a weakness that could be exploited by that threat</strong> — a threat is the potential source of harm (e.g., a malicious actor or natural event), whereas a vulnerability is the weakness in an asset or control that the threat could exploit to cause harm.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A threat is a weakness that can be exploited, while a vulnerability is the entity that exploits it</b>: this reverses the correct definitions of the two terms.</span><span class='qd'><b>There is no practical distinction between the two terms</b>: the distinction is fundamental to risk analysis, since risk arises only from the pairing of the two.</span><span class='qd'><b>A vulnerability always results in a loss, while a threat never does</b>: neither a vulnerability nor a threat alone guarantees a loss; loss requires both risk factors combined with exploitation.</span>"},
{"id":"D2-025","domain":2,"obj":"2A1","diff":"easy","q":"Which of the following is an example of a vulnerability rather than a threat?","options":["A disgruntled employee","A hurricane","An unpatched operating system","A malicious external attacker"],"answer":2,"explain":"<strong>An unpatched operating system</strong> — a missing patch is a weakness in the system that could be exploited, making it a vulnerability rather than a source of harm itself.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A disgruntled employee</b>: represents a potential source of harm (an insider threat actor), not a weakness.</span><span class='qd'><b>A hurricane</b>: is an environmental/natural threat source, not a system weakness.</span><span class='qd'><b>A malicious external attacker</b>: represents a threat actor, not a vulnerability.</span>"},
{"id":"D2-026","domain":2,"obj":"2B5","diff":"hard","q":"After implementing a new set of access controls, an information security manager wants to determine the risk that remains. This remaining risk is BEST known as:","options":["Inherent risk","Control risk","Aggregate risk","Residual risk"],"answer":3,"explain":"<strong>Residual risk</strong> — this is the risk that remains after controls have been applied to reduce the inherent risk; management must compare it against the risk appetite to decide whether further treatment is needed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Inherent risk</b>: is the level of risk before any controls are applied, the opposite of what is being asked.</span><span class='qd'><b>Control risk</b>: refers to the possibility that a control itself fails to operate as intended, a related but distinct concept.</span><span class='qd'><b>Aggregate risk</b>: refers to the combined risk across multiple sources or systems, not the specific post-control remainder for a single risk.</span>"},
{"id":"D2-027","domain":2,"obj":"2B5","diff":"med","q":"Residual risk for a critical application remains above the organization's defined risk tolerance even after compensating controls were implemented. What should the information security manager do NEXT?","options":["Close the risk in the register since controls were already implemented","Present the residual risk to the appropriate risk owner for a formal decision on further treatment or documented acceptance","Unilaterally accept the risk on behalf of the business to save time","Remove the application from production without consulting stakeholders"],"answer":1,"explain":"<strong>Present the residual risk to the appropriate risk owner for a formal decision on further treatment or documented acceptance</strong> — when residual risk exceeds tolerance, the accountable risk owner must decide whether to apply further treatment, request additional resources, or formally accept the risk; this decision is outside the security manager's sole authority.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Close the risk in the register since controls were already implemented</b>: closing the risk while it still exceeds tolerance misrepresents the organization's actual exposure.</span><span class='qd'><b>Unilaterally accept the risk on behalf of the business to save time</b>: acceptance decisions exceeding tolerance require authority the security manager typically does not hold alone.</span><span class='qd'><b>Remove the application from production without consulting stakeholders</b>: an operational decision of this magnitude requires business consultation, not unilateral action.</span>"},
{"id":"D2-028","domain":2,"obj":"2A2","diff":"easy","q":"A business unit manager insists on accepting a high risk that exceeds the organization's documented risk appetite, without escalation. What is the information security manager's MOST appropriate course of action?","options":["Allow the acceptance since the business unit manager owns the risk","Document the exception and escalate it to a level of management or governance body with the authority to approve exceptions to risk appetite","Publicly overrule the business unit manager's decision without escalation","Ignore the issue since business decisions are outside the scope of security"],"answer":1,"explain":"<strong>Document the exception and escalate it to a level of management or governance body with the authority to approve exceptions to risk appetite</strong> — risk acceptance beyond established appetite requires approval from a governance level with sufficient authority; the security manager's role is to ensure this escalation occurs and is documented.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Allow the acceptance since the business unit manager owns the risk</b>: ownership does not grant authority to exceed board- or executive-approved appetite thresholds unilaterally.</span><span class='qd'><b>Publicly overrule the business unit manager's decision without escalation</b>: overruling without proper escalation bypasses governance and may create conflict without resolving the underlying authority gap.</span><span class='qd'><b>Ignore the issue since business decisions are outside the scope of security</b>: appetite breaches are a governance concern that the security manager is responsible for surfacing.</span>"},
{"id":"D2-029","domain":2,"obj":"2A4","diff":"med","q":"An organization's board sets a risk appetite statement that conflicts with a specific business unit's operational risk tolerance thresholds already in place. What should the information security manager recommend?","options":["Reconcile the business unit's tolerance thresholds with the board-approved appetite to ensure consistency, escalating unresolved conflicts to governance","Ignore the board-level statement since operational thresholds are more practical","Allow both to remain in conflict since they apply to different levels of the organization","Replace the board's risk appetite statement with the business unit's thresholds"],"answer":0,"explain":"<strong>Reconcile the business unit's tolerance thresholds with the board-approved appetite to ensure consistency, escalating unresolved conflicts to governance</strong> — tolerance thresholds should operationalize, not contradict, the board's risk appetite; misalignment must be reconciled and any unresolved conflict escalated to the appropriate governance body.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore the board-level statement since operational thresholds are more practical</b>: disregarding board-approved appetite undermines governance and enterprise-wide consistency.</span><span class='qd'><b>Allow both to remain in conflict since they apply to different levels of the organization</b>: unresolved conflicts create inconsistent risk decisions and governance gaps that should be addressed, not tolerated.</span><span class='qd'><b>Replace the board's risk appetite statement with the business unit's thresholds</b>: a business unit does not have the authority to override the board's strategic risk appetite.</span>"},
{"id":"D2-030","domain":2,"obj":"2B6","diff":"hard","q":"Which of the following is the PRIMARY reason for conducting periodic reassessment of previously identified and treated risks?","options":["To satisfy a fixed annual audit requirement only","To reduce the total number of entries in the risk register","To confirm that the risk environment, controls, and business context have not changed in ways that affect the risk's current level or treatment adequacy","To eliminate the need for new risk assessments on future projects"],"answer":2,"explain":"<strong>To confirm that the risk environment, controls, and business context have not changed in ways that affect the risk's current level or treatment adequacy</strong> — risks are dynamic; periodic reassessment ensures that changes in threats, vulnerabilities, controls, or business context are reflected so treatment decisions remain appropriate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>To satisfy a fixed annual audit requirement only</b>: while audits may prompt review, the underlying purpose is maintaining an accurate and current risk picture, not merely satisfying a compliance calendar.</span><span class='qd'><b>To reduce the total number of entries in the risk register</b>: reassessment aims for accuracy, not artificially reducing the register's size.</span><span class='qd'><b>To eliminate the need for new risk assessments on future projects</b>: reassessing existing risks does not replace the need to assess risk on new initiatives.</span>"},
{"id":"D2-031","domain":2,"obj":"2A1","diff":"med","q":"Which term BEST describes a structured process for identifying, analyzing, evaluating, and treating risks to organizational assets?","options":["Incident response","Risk management","Change management","Business continuity planning"],"answer":1,"explain":"<strong>Risk management</strong> — this is the overarching, structured discipline encompassing identification, analysis, evaluation, and treatment of risk to protect organizational assets and objectives.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Incident response</b>: focuses on detecting and responding to security events after they occur, not the broader risk lifecycle.</span><span class='qd'><b>Change management</b>: governs how changes to systems are controlled, a different discipline entirely.</span><span class='qd'><b>Business continuity planning</b>: focuses specifically on maintaining operations during disruption, a subset activity informed by risk management but not synonymous with it.</span>"},
{"id":"D2-032","domain":2,"obj":"2A1","diff":"easy","q":"During the risk identification phase, which source is MOST useful for uncovering risks specific to a new software application before it goes live?","options":["Prior year's employee satisfaction survey","General industry threat intelligence unrelated to the application","The organization's annual holiday schedule","Architecture and design documentation combined with threat modeling of the application"],"answer":3,"explain":"<strong>Architecture and design documentation combined with threat modeling of the application</strong> — reviewing how the application is built and systematically modeling threats against its specific architecture surfaces risks unique to that system before deployment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Prior year's employee satisfaction survey</b>: is unrelated to technical or application-specific risk identification.</span><span class='qd'><b>General industry threat intelligence unrelated to the application</b>: provides useful context but is not specific enough to identify risks unique to this application's design.</span><span class='qd'><b>The organization's annual holiday schedule</b>: has no bearing on identifying application security risks.</span>"},
{"id":"D2-033","domain":2,"obj":"2B2","diff":"med","q":"An organization values a customer database at $1,200,000. A ransomware attack is estimated to cause a 60% loss of value and is expected to occur once every two years. What is the ALE?","options":["$360,000","$720,000","$600,000","$240,000"],"answer":0,"explain":"<strong>$360,000</strong> — SLE = AV x EF = $1,200,000 x 0.60 = $720,000. ARO = 1/2 = 0.5. ALE = SLE x ARO = $720,000 x 0.5 = $360,000.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>$720,000</b>: this is the SLE only, without applying the annualized rate of occurrence.</span><span class='qd'><b>$600,000</b>: does not result from correctly multiplying the given SLE and ARO.</span><span class='qd'><b>$240,000</b>: results from an incorrect exposure factor calculation rather than the given 60%.</span>"},
{"id":"D2-034","domain":2,"obj":"2B2","diff":"hard","q":"A control costing $12,000 per year is expected to reduce ALE from $50,000 to $30,000. What is the ROSI?","options":["40%","67%","20%","167%"],"answer":1,"explain":"<strong>67%</strong> — ROSI = (Risk reduction - Cost of control) / Cost of control = (($50,000 - $30,000) - $12,000) / $12,000 = $8,000 / $12,000 = 0.667 = 67%.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>40%</b>: does not match the correct net-benefit-over-cost calculation using the figures given.</span><span class='qd'><b>20%</b>: results from using an incorrect risk reduction figure rather than the correct $20,000 reduction.</span><span class='qd'><b>167%</b>: represents the gross benefit-to-cost ratio ($20,000/$12,000) without subtracting appropriately to form net ROSI.</span>"},
{"id":"D2-035","domain":2,"obj":"2A3","diff":"easy","q":"Which of the following BEST describes a semi-quantitative risk analysis approach?","options":["Using only descriptive terms such as high, medium, and low with no numeric scoring at all","Calculating exact monetary loss figures using verified historical data exclusively","Assigning numeric scores or weighted rankings to qualitative categories to allow relative comparison without precise monetary values","Relying solely on regulatory checklists without any risk scoring"],"answer":2,"explain":"<strong>Assigning numeric scores or weighted rankings to qualitative categories to allow relative comparison without precise monetary values</strong> — semi-quantitative analysis blends the descriptive nature of qualitative methods with numeric scoring or weighting, enabling relative comparison and prioritization without requiring precise monetary data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Using only descriptive terms such as high, medium, and low with no numeric scoring at all</b>: this describes purely qualitative analysis, not the semi-quantitative approach.</span><span class='qd'><b>Calculating exact monetary loss figures using verified historical data exclusively</b>: this describes purely quantitative analysis.</span><span class='qd'><b>Relying solely on regulatory checklists without any risk scoring</b>: a compliance checklist approach does not constitute risk analysis at all.</span>"},
{"id":"D2-036","domain":2,"obj":"2A3","diff":"med","q":"A key limitation of qualitative risk analysis, compared to quantitative analysis, is that it:","options":["Cannot be performed without extensive historical loss data","Introduces subjectivity and may make cost-benefit comparisons across risks less precise","Always takes longer to complete than quantitative analysis","Cannot be used for information security risk at all"],"answer":1,"explain":"<strong>Introduces subjectivity and may make cost-benefit comparisons across risks less precise</strong> — because qualitative analysis relies on descriptive ratings and expert judgment rather than precise figures, it is inherently more subjective and less suited to fine-grained financial cost-benefit comparisons.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Cannot be performed without extensive historical loss data</b>: qualitative analysis is actually preferred precisely because it does not require extensive historical data.</span><span class='qd'><b>Always takes longer to complete than quantitative analysis</b>: qualitative analysis is generally faster, not slower, than rigorous quantitative modeling.</span><span class='qd'><b>Cannot be used for information security risk at all</b>: qualitative analysis is widely and appropriately used for information security risk assessment.</span>"},
{"id":"D2-037","domain":2,"obj":"2B3","diff":"med","q":"An organization implements multi-factor authentication and network segmentation to reduce the likelihood and impact of unauthorized access to a sensitive system. This is an example of which risk treatment?","options":["Risk avoidance","Risk mitigation","Risk transfer","Risk acceptance"],"answer":1,"explain":"<strong>Risk mitigation</strong> — implementing controls such as multi-factor authentication and segmentation directly reduces the likelihood or impact of the risk, which is the defining characteristic of mitigation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk avoidance</b>: would mean eliminating the activity or system entirely rather than adding controls to it.</span><span class='qd'><b>Risk transfer</b>: would involve shifting the financial or operational impact to a third party, not implementing internal controls.</span><span class='qd'><b>Risk acceptance</b>: would mean taking no additional action and tolerating the risk as-is.</span>"},
{"id":"D2-038","domain":2,"obj":"2B3","diff":"hard","q":"A CFO decides to outsource payment card processing entirely to a PCI DSS-compliant third-party processor specifically to shift the compliance burden and much of the associated risk away from the organization. This is BEST classified as:","options":["Risk mitigation only","Risk acceptance, since some residual risk always remains with the organization","A combination of risk transfer and risk avoidance, since both the processing activity and its associated liability are shifted away from the organization","Pure risk avoidance with no transfer element"],"answer":2,"explain":"<strong>A combination of risk transfer and risk avoidance, since both the processing activity and its associated liability are shifted away from the organization</strong> — outsourcing to a compliant processor both removes the organization from directly performing the risky activity (avoidance-like effect) and shifts liability/compliance burden to the third party (transfer), making this a blended treatment in practice, though the organization retains residual vendor-management risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk mitigation only</b>: mitigation implies retaining the activity while reducing risk through internal controls, not shifting the activity itself.</span><span class='qd'><b>Risk acceptance, since some residual risk always remains with the organization</b>: while residual vendor risk exists, the primary treatment strategy applied is transfer/avoidance, not passive acceptance.</span><span class='qd'><b>Pure risk avoidance with no transfer element</b>: ignores the clear transfer of liability and compliance burden to the processor.</span>"},
{"id":"D2-039","domain":2,"obj":"2B3","diff":"easy","q":"Which risk treatment option involves taking NO action to reduce, transfer, or eliminate a risk, based on an informed and authorized decision?","options":["Risk acceptance","Risk mitigation","Risk avoidance","Risk transfer"],"answer":0,"explain":"<strong>Risk acceptance</strong> — this treatment involves consciously choosing to retain the risk as-is, based on an authorized decision that the risk is within tolerance or that treatment costs exceed the benefit.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk mitigation</b>: involves actively reducing the risk through controls, which is action, not inaction.</span><span class='qd'><b>Risk avoidance</b>: involves eliminating the risk by discontinuing the associated activity.</span><span class='qd'><b>Risk transfer</b>: involves shifting impact to a third party, which requires an active arrangement such as insurance or outsourcing.</span>"},
{"id":"D2-040","domain":2,"obj":"2A4","diff":"med","q":"Which of the following would MOST likely trigger a review and potential revision of an organization's risk appetite statement?","options":["A major shift in business strategy, such as entry into a new highly regulated market","A routine password reset for a single user account","A minor software patch applied to a non-critical workstation","The scheduled rotation of a firewall administrator's access credentials"],"answer":0,"explain":"<strong>A major shift in business strategy, such as entry into a new highly regulated market</strong> — significant strategic changes alter the organization's risk landscape and regulatory exposure, warranting a reassessment of how much risk the organization is willing to accept in pursuit of its objectives.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A routine password reset for a single user account</b>: is a routine operational event with no strategic risk implication.</span><span class='qd'><b>A minor software patch applied to a non-critical workstation</b>: is a minor operational change unlikely to affect enterprise-wide risk appetite.</span><span class='qd'><b>The scheduled rotation of a firewall administrator's access credentials</b>: is standard access management practice, not a strategic trigger.</span>"},
{"id":"D2-041","domain":2,"obj":"2A4","diff":"easy","q":"A newly appointed CISO observes that individual departments consistently make risk acceptance decisions that, in aggregate, exceed the enterprise risk appetite even though each decision alone appears within its own local tolerance. What does this scenario BEST illustrate?","options":["That local tolerance thresholds are irrelevant and should be eliminated","The need to aggregate and view risk acceptance decisions at an enterprise level rather than only in isolated silos","That risk appetite statements are only symbolic and have no practical use","That each department should be allowed to set its own independent appetite"],"answer":1,"explain":"<strong>The need to aggregate and view risk acceptance decisions at an enterprise level rather than only in isolated silos</strong> — individually acceptable risks can combine to exceed overall enterprise appetite; effective risk governance requires an aggregated, enterprise-wide view, not just isolated departmental assessments.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>That local tolerance thresholds are irrelevant and should be eliminated</b>: local thresholds remain useful for operational decisions; the issue is the lack of aggregation, not the thresholds' existence.</span><span class='qd'><b>That risk appetite statements are only symbolic and have no practical use</b>: the appetite statement is meaningful; the gap is in the process for aggregating exposure against it.</span><span class='qd'><b>That each department should be allowed to set its own independent appetite</b>: independent, uncoordinated appetites would worsen the aggregation problem described.</span>"},
{"id":"D2-042","domain":2,"obj":"2B1","diff":"med","q":"An organization tracks the percentage of critical vulnerabilities remaining unpatched beyond the defined SLA window as a leading metric to flag rising exposure. This metric is an example of a:","options":["Key performance indicator (KPI) only, unrelated to risk","Key control indicator with no risk relevance","Key risk indicator (KRI)","Balanced scorecard financial metric"],"answer":2,"explain":"<strong>Key risk indicator (KRI)</strong> — tracking overdue critical vulnerabilities against an SLA threshold provides early warning that exposure to exploitation is rising, which is precisely the purpose of a KRI.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Key performance indicator (KPI) only, unrelated to risk</b>: while it can also serve as a KPI for patch management performance, its primary framing here as an early-warning exposure signal makes it a KRI.</span><span class='qd'><b>Key control indicator with no risk relevance</b>: it does have direct risk relevance since overdue patches represent rising vulnerability exposure.</span><span class='qd'><b>Balanced scorecard financial metric</b>: this metric is operational/technical, not a financial scorecard measure.</span>"},
{"id":"D2-043","domain":2,"obj":"2B1","diff":"hard","q":"An information security manager notices that a chosen KRI (number of failed login attempts per day) has remained flat for two years despite significant changes in the threat landscape and user base growth. What is the MOST likely conclusion?","options":["The organization's risk level has genuinely remained completely unchanged","The KRI should be reported less frequently since it never changes","The KRI may no longer be sensitive or relevant enough to reflect actual changes in risk and should be reviewed or recalibrated","All other risk indicators should be discontinued as unnecessary"],"answer":2,"explain":"<strong>The KRI may no longer be sensitive or relevant enough to reflect actual changes in risk and should be reviewed or recalibrated</strong> — a static metric despite known environmental changes suggests it has lost sensitivity or relevance, and effective KRIs must be periodically reviewed and recalibrated to remain meaningful.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The organization's risk level has genuinely remained completely unchanged</b>: given the stated threat landscape and user growth changes, an unchanging metric more likely signals a flawed indicator than a static risk level.</span><span class='qd'><b>The KRI should be reported less frequently since it never changes</b>: reducing reporting frequency does not address the underlying concern that the metric may be ineffective.</span><span class='qd'><b>All other risk indicators should be discontinued as unnecessary</b>: this conclusion is unsupported and disproportionate to the observation about a single metric.</span>"},
{"id":"D2-044","domain":2,"obj":"2B4","diff":"med","q":"Which of the following is the BEST way to manage ongoing risk from third-party vendors after the initial contract is signed?","options":["Conduct due diligence once at contract signing and assume risk remains constant thereafter","Rely exclusively on the vendor's self-reported assurances with no independent verification","Terminate all vendor contracts after one year regardless of performance","Establish continuous or periodic monitoring of vendor security posture, performance against SLAs, and any changes in the vendor's risk profile"],"answer":3,"explain":"<strong>Establish continuous or periodic monitoring of vendor security posture, performance against SLAs, and any changes in the vendor's risk profile</strong> — third-party risk is dynamic; ongoing monitoring ensures that changes in the vendor's control environment, incidents, or performance are identified and addressed throughout the relationship.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Conduct due diligence once at contract signing and assume risk remains constant thereafter</b>: vendor risk can change significantly over time, so a one-time assessment is insufficient.</span><span class='qd'><b>Rely exclusively on the vendor's self-reported assurances with no independent verification</b>: unverified self-attestation provides weak assurance and should be supplemented with independent evidence.</span><span class='qd'><b>Terminate all vendor contracts after one year regardless of performance</b>: arbitrary termination is impractical and unrelated to actual risk management.</span>"},
{"id":"D2-045","domain":2,"obj":"2B4","diff":"easy","q":"When assessing fourth-party risk (a vendor's own subcontractors and suppliers), which action is MOST appropriate for the information security manager?","options":["Ignore fourth parties since the organization has no direct contractual relationship with them","Assume the primary vendor's certification alone fully covers all subcontractor risk with no further inquiry","Require the primary vendor to demonstrate that it adequately manages and monitors risk introduced by its own subcontractors","Contact each subcontractor directly and bypass the primary vendor entirely"],"answer":2,"explain":"<strong>Require the primary vendor to demonstrate that it adequately manages and monitors risk introduced by its own subcontractors</strong> — since the organization typically lacks direct contractual leverage over fourth parties, the most practical control is holding the primary vendor accountable for managing its own supply chain risk, often through contractual flow-down requirements.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ignore fourth parties since the organization has no direct contractual relationship with them</b>: fourth-party risk can still materially affect the organization's data and operations and should not be ignored.</span><span class='qd'><b>Assume the primary vendor's certification alone fully covers all subcontractor risk with no further inquiry</b>: certification scope may not extend to every subcontractor, so blind assumption is risky.</span><span class='qd'><b>Contact each subcontractor directly and bypass the primary vendor entirely</b>: bypassing the primary vendor undermines the contractual relationship and is often impractical at scale.</span>"},
{"id":"D2-046","domain":2,"obj":"2A5","diff":"hard","q":"An enterprise risk committee wants to compare information security risk against operational, financial, and reputational risk on a single heat map for board reporting. What is the MOST important prerequisite for this comparison to be meaningful?","options":["All risks must be expressed only in qualitative terms with no numeric scoring","The board must review only information security risks separately from other categories","Each risk category must use a completely different scale tailored to its own department","All risk categories must use a consistent likelihood and impact scale so ratings are comparable across categories"],"answer":3,"explain":"<strong>All risk categories must use a consistent likelihood and impact scale so ratings are comparable across categories</strong> — a single heat map is only meaningful if every risk category is scored against the same likelihood and impact definitions, allowing fair, apples-to-apples comparison and prioritization.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>All risks must be expressed only in qualitative terms with no numeric scoring</b>: consistency of scale matters more than whether the scale is qualitative or quantitative.</span><span class='qd'><b>The board must review only information security risks separately from other categories</b>: separating categories defeats the stated purpose of an integrated enterprise comparison.</span><span class='qd'><b>Each risk category must use a completely different scale tailored to its own department</b>: differing scales would make the combined heat map incomparable and misleading.</span>"},
{"id":"D2-047","domain":2,"obj":"2A2","diff":"med","q":"A control owner reports that a key control has failed a recent test. Who is PRIMARILY responsible for deciding what additional risk treatment, if any, is required as a result?","options":["The risk owner, in consultation with the control owner and information security","The control owner alone, without further escalation","The external auditor who identified the test result","The help desk team that manages user tickets"],"answer":0,"explain":"<strong>The risk owner, in consultation with the control owner and information security</strong> — while the control owner reports the failure and provides technical context, the risk owner is accountable for the underlying risk and must decide on further treatment, informed by input from the control owner and security function.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The control owner alone, without further escalation</b>: the control owner manages the specific control but does not hold overall accountability for the business risk outcome.</span><span class='qd'><b>The external auditor who identified the test result</b>: auditors provide independent assurance and findings but do not make risk treatment decisions for the organization.</span><span class='qd'><b>The help desk team that manages user tickets</b>: this team has no role in risk treatment decision-making.</span>"},
{"id":"D2-048","domain":2,"obj":"2B2","diff":"easy","q":"An organization's server room is valued at $400,000. A fire risk assessment determines an exposure factor of 75% and an ARO of 0.1 (once every 10 years). What is the ALE?","options":["$40,000","$30,000","$300,000","$4,000"],"answer":1,"explain":"<strong>$30,000</strong> — SLE = AV x EF = $400,000 x 0.75 = $300,000. ALE = SLE x ARO = $300,000 x 0.1 = $30,000.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>$40,000</b>: does not result from correctly applying both the exposure factor and the annualized rate of occurrence.</span><span class='qd'><b>$300,000</b>: this is the SLE only, without applying the ARO.</span><span class='qd'><b>$4,000</b>: results from an incorrect exposure factor rather than the given 75%.</span>"},
{"id":"D2-049","domain":2,"obj":"2B2","diff":"med","q":"A data loss prevention (DLP) solution costs $45,000 annually and is projected to reduce ALE from $150,000 to $90,000. What is the ROSI?","options":["25%","50%","33%","20%"],"answer":2,"explain":"<strong>33%</strong> — ROSI = (Risk reduction - Cost of control) / Cost of control = (($150,000 - $90,000) - $45,000) / $45,000 = $15,000 / $45,000 = 0.333 = 33%.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>25%</b>: does not correspond to the correct net-benefit-over-cost calculation with these figures.</span><span class='qd'><b>50%</b>: overstates the result by using an incorrect risk reduction or cost figure.</span><span class='qd'><b>20%</b>: understates the ROSI relative to the correct calculation using the given numbers.</span>"},
{"id":"D2-050","domain":2,"obj":"2A3","diff":"hard","q":"A Delphi technique workshop is used to gather independent, anonymous input from subject matter experts on the likelihood of a novel threat before combining their views into a consensus rating. This technique is MOST commonly associated with which type of risk analysis?","options":["Purely quantitative analysis based on historical loss data","Automated vulnerability scanning","Regulatory compliance checklist review","Qualitative or semi-quantitative analysis relying on expert judgment"],"answer":3,"explain":"<strong>Qualitative or semi-quantitative analysis relying on expert judgment</strong> — the Delphi technique is a structured method for building expert consensus on likelihood or impact ratings, commonly used in qualitative or semi-quantitative risk analysis where hard data is limited.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Purely quantitative analysis based on historical loss data</b>: Delphi is used specifically because historical data may be insufficient, not as a substitute for quantitative modeling.</span><span class='qd'><b>Automated vulnerability scanning</b>: is a technical detection activity, unrelated to expert consensus-building.</span><span class='qd'><b>Regulatory compliance checklist review</b>: is a compliance verification activity, not a risk analysis technique.</span>"},
{"id":"D2-051","domain":2,"obj":"2A1","diff":"med","q":"An information security manager is prioritizing which risks to analyze in depth first. Which factor should MOST influence this prioritization?","options":["The potential business impact and likelihood associated with each identified risk","The alphabetical order of the asset names in inventory","The number of employees who reported the risk","The age of the asset regardless of its criticality"],"answer":0,"explain":"<strong>The potential business impact and likelihood associated with each identified risk</strong> — prioritization should focus limited analysis resources on risks with the greatest potential impact and likelihood, ensuring the most significant exposures are addressed first.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The alphabetical order of the asset names in inventory</b>: is an arbitrary criterion unrelated to actual risk significance.</span><span class='qd'><b>The number of employees who reported the risk</b>: popularity of reporting does not necessarily correlate with actual business impact or likelihood.</span><span class='qd'><b>The age of the asset regardless of its criticality</b>: age alone, without considering business criticality, is an incomplete prioritization criterion.</span>"},
{"id":"D2-052","domain":2,"obj":"2B6","diff":"easy","q":"Which event would MOST likely require an unscheduled, ad hoc reassessment of a previously accepted risk, outside the normal periodic review cycle?","options":["A significant new vulnerability is publicly disclosed affecting a control the organization relies on for that risk","The annual holiday calendar is published","The organization's logo is redesigned","A routine employee satisfaction survey is conducted"],"answer":0,"explain":"<strong>A significant new vulnerability is publicly disclosed affecting a control the organization relies on for that risk</strong> — a material change such as a newly disclosed vulnerability affecting a relied-upon control can invalidate the basis of a prior risk acceptance, warranting immediate reassessment rather than waiting for the next scheduled cycle.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The annual holiday calendar is published</b>: has no bearing on the organization's risk posture.</span><span class='qd'><b>The organization's logo is redesigned</b>: is a branding change unrelated to risk exposure.</span><span class='qd'><b>A routine employee satisfaction survey is conducted</b>: is an HR activity unrelated to the technical or control basis of the risk.</span>"},
{"id":"D2-053","domain":2,"obj":"2B5","diff":"med","q":"Which of the following BEST describes 'control risk' as distinct from inherent and residual risk?","options":["The risk that remains after all controls are applied","The risk that exists before any controls are considered","The total combined risk across the entire organization","The risk that a control fails to operate as designed or intended, potentially allowing inherent risk to persist unmitigated"],"answer":3,"explain":"<strong>The risk that a control fails to operate as designed or intended, potentially allowing inherent risk to persist unmitigated</strong> — control risk specifically addresses the possibility that a control does not perform as expected, which is a distinct concept from the risk levels before (inherent) or after (residual) controls are theoretically applied.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The risk that remains after all controls are applied</b>: this describes residual risk, not control risk.</span><span class='qd'><b>The risk that exists before any controls are considered</b>: this describes inherent risk, not control risk.</span><span class='qd'><b>The total combined risk across the entire organization</b>: this describes an aggregate or enterprise risk view, not the specific concept of control risk.</span>"},
{"id":"D2-054","domain":2,"obj":"2B5","diff":"hard","q":"An internal audit reveals that a compensating control assumed to reduce a risk's likelihood has actually never been operating effectively since implementation. What is the MOST accurate characterization of the risk currently facing the organization?","options":["The residual risk is unaffected since the control was documented as implemented","The residual risk is materially higher than previously reported, closer to the inherent risk level, due to control risk being realized","The inherent risk has decreased as a result of this finding","The organization should immediately transfer all risk via insurance regardless of cost"],"answer":1,"explain":"<strong>The residual risk is materially higher than previously reported, closer to the inherent risk level, due to control risk being realized</strong> — if the assumed control was never operating effectively, the actual risk reduction never occurred, meaning the true residual risk has remained close to the inherent level and was understated in prior reporting.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The residual risk is unaffected since the control was documented as implemented</b>: documentation alone does not reduce risk; operating effectiveness is what matters.</span><span class='qd'><b>The inherent risk has decreased as a result of this finding</b>: inherent risk is independent of controls and is not affected by this discovery.</span><span class='qd'><b>The organization should immediately transfer all risk via insurance regardless of cost</b>: jumping to a specific costly treatment without proper analysis and risk owner involvement is premature.</span>"},
{"id":"D2-055","domain":2,"obj":"2A2","diff":"easy","q":"Which statement about risk ownership is MOST accurate?","options":["A risk can have multiple owners simultaneously with no accountability issues","Risk ownership is only relevant for technical, IT-specific risks","Only the CEO can be a risk owner in any organization","Every risk should have a single accountable owner to ensure clear decision-making authority"],"answer":3,"explain":"<strong>Every risk should have a single accountable owner to ensure clear decision-making authority</strong> — assigning one accountable owner per risk avoids diffusion of responsibility and ensures clear authority over treatment and acceptance decisions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A risk can have multiple owners simultaneously with no accountability issues</b>: multiple owners typically dilute accountability and can lead to gaps or conflicting decisions.</span><span class='qd'><b>Risk ownership is only relevant for technical, IT-specific risks</b>: risk ownership applies broadly across financial, operational, reputational, and other business risks, not just IT.</span><span class='qd'><b>Only the CEO can be a risk owner in any organization</b>: ownership is typically delegated to the appropriate accountable manager for each specific risk, not centralized solely in the CEO.</span>"},
{"id":"D2-056","domain":2,"obj":"2B1","diff":"med","q":"Which of the following would be the MOST effective key risk indicator for monitoring the risk of insider data exfiltration?","options":["Total number of employees hired in the quarter","Number of new office locations opened","Volume of data transferred to unauthorized or unusual external destinations detected by DLP tooling","Average employee tenure across the company"],"answer":2,"explain":"<strong>Volume of data transferred to unauthorized or unusual external destinations detected by DLP tooling</strong> — this metric is directly and specifically relevant to the risk being monitored, providing an early, measurable signal of potential data exfiltration activity.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Total number of employees hired in the quarter</b>: hiring volume alone does not meaningfully indicate exfiltration risk.</span><span class='qd'><b>Number of new office locations opened</b>: is unrelated to insider data exfiltration risk.</span><span class='qd'><b>Average employee tenure across the company</b>: while tenure might correlate loosely with some risk factors, it is far less direct and actionable than DLP-based exfiltration signals.</span>"},
{"id":"D2-057","domain":2,"obj":"2B4","diff":"med","q":"A vendor risk assessment questionnaire reveals that a critical SaaS provider does not encrypt data at rest. What is the information security manager's BEST immediate action?","options":["Terminate the vendor relationship immediately without further discussion","Document the finding as a risk, evaluate its significance against the data's sensitivity, and work with the vendor and risk owner on remediation or compensating controls","Ignore the finding since encryption at rest is not commonly required","Approve the vendor without conditions since the questionnaire was completed"],"answer":1,"explain":"<strong>Document the finding as a risk, evaluate its significance against the data's sensitivity, and work with the vendor and risk owner on remediation or compensating controls</strong> — a structured response captures the finding in the risk process, assesses its actual significance based on data sensitivity, and pursues remediation or compensating controls collaboratively with the risk owner before deciding on next steps.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Terminate the vendor relationship immediately without further discussion</b>: an immediate termination is disproportionate without first assessing significance and remediation options.</span><span class='qd'><b>Ignore the finding since encryption at rest is not commonly required</b>: encryption at rest is a standard control expectation for sensitive data and should not be dismissed.</span><span class='qd'><b>Approve the vendor without conditions since the questionnaire was completed</b>: completing a questionnaire does not substitute for addressing a material identified gap.</span>"},
{"id":"D2-058","domain":2,"obj":"2A5","diff":"hard","q":"Which of the following BEST demonstrates that information security risk management is well integrated with enterprise risk management (ERM)?","options":["Information security maintains a completely separate risk register that no other department can access","The security team makes independent risk acceptance decisions without informing the enterprise risk function","Enterprise risk management is unaware that an information security function exists","Information security risks are reported and reviewed in the same governance forums, using the same criteria, as other enterprise risk categories"],"answer":3,"explain":"<strong>Information security risks are reported and reviewed in the same governance forums, using the same criteria, as other enterprise risk categories</strong> — true integration means security risk is visible to, and evaluated consistently within, the same enterprise governance structures and criteria used for all other risk categories.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Information security maintains a completely separate risk register that no other department can access</b>: isolation of the register from broader visibility is the opposite of integration.</span><span class='qd'><b>The security team makes independent risk acceptance decisions without informing the enterprise risk function</b>: independent, siloed decision-making without ERM visibility undermines integration.</span><span class='qd'><b>Enterprise risk management is unaware that an information security function exists</b>: this describes a complete lack of integration, not its presence.</span>"},
{"id":"D2-059","domain":2,"obj":"2A4","diff":"easy","q":"An organization's risk tolerance for customer data breaches is set at zero incidents involving regulated personal data per year. This reflects which underlying driver of risk tolerance setting?","options":["Purely arbitrary preference of the security team with no external driver","A desire to minimize IT department headcount","Regulatory, legal, and reputational considerations tied to protecting regulated personal data","Random selection unrelated to business context"],"answer":2,"explain":"<strong>Regulatory, legal, and reputational considerations tied to protecting regulated personal data</strong> — a zero-tolerance threshold for breaches of regulated personal data typically reflects the severe legal, regulatory, and reputational consequences the organization associates with such events.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Purely arbitrary preference of the security team with no external driver</b>: tolerance thresholds for regulated data are typically driven by real external legal and regulatory obligations, not arbitrary preference.</span><span class='qd'><b>A desire to minimize IT department headcount</b>: staffing levels are unrelated to why a specific tolerance threshold is set.</span><span class='qd'><b>Random selection unrelated to business context</b>: tolerance settings should always be grounded in business context and consequence severity, not randomness.</span>"},
{"id":"D2-060","domain":2,"obj":"2B6","diff":"med","q":"Which of the following BEST supports maintaining an accurate and current risk register over time?","options":["Updating the register only when a major breach occurs","Deleting entries automatically after one year regardless of status","Establishing a defined process for periodic review, along with triggers for ad hoc updates when significant changes occur","Allowing only one person in the entire organization to ever view the register"],"answer":2,"explain":"<strong>Establishing a defined process for periodic review, along with triggers for ad hoc updates when significant changes occur</strong> — a combination of scheduled periodic reviews and event-driven triggers ensures the register reflects both routine changes and significant unplanned developments in the risk environment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Updating the register only when a major breach occurs</b>: waiting for a breach means the register is reactive rather than proactively maintained.</span><span class='qd'><b>Deleting entries automatically after one year regardless of status</b>: arbitrary deletion regardless of actual risk status would remove valid, still-relevant risks.</span><span class='qd'><b>Allowing only one person in the entire organization to ever view the register</b>: overly restrictive access undermines the collaborative use of the register by risk and control owners.</span>"},
{"id":"D2-061","domain":2,"obj":"2A1","diff":"easy","q":"During a risk identification workshop, participants disagree on whether a specific scenario (a cloud misconfiguration exposing data) should be classified as a single risk or split into multiple related risks. What is the BEST guiding principle for this decision?","options":["Always combine all related scenarios into a single generic risk entry to minimize register size","Always split every scenario into the maximum possible number of separate risks","Let the most senior person in the room decide arbitrarily without further criteria","Define risks at a level of granularity that supports meaningful, distinct treatment and ownership decisions"],"answer":3,"explain":"<strong>Define risks at a level of granularity that supports meaningful, distinct treatment and ownership decisions</strong> — the right level of granularity is the one that allows each risk to be clearly owned, analyzed, and treated; scenarios that require different owners or treatments generally warrant separate entries, while closely related aspects of the same exposure may be combined.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Always combine all related scenarios into a single generic risk entry to minimize register size</b>: over-combining can obscure distinct treatment needs and ownership, weakening the register's usefulness.</span><span class='qd'><b>Always split every scenario into the maximum possible number of separate risks</b>: excessive splitting can create redundant, unmanageable entries without adding decision-making value.</span><span class='qd'><b>Let the most senior person in the room decide arbitrarily without further criteria</b>: an arbitrary decision without guiding criteria risks inconsistency across the register.</span>"},
{"id":"D2-062","domain":2,"obj":"2B2","diff":"med","q":"An organization is comparing two controls for the same risk. Control A costs $20,000/year and reduces ALE from $80,000 to $50,000. Control B costs $35,000/year and reduces ALE from $80,000 to $20,000. Based on ROSI alone, which control is the better investment?","options":["Control B, with a ROSI of approximately 71% versus Control A's ROSI of 50%","Control A, with a ROSI of 50% versus Control B's ROSI of approximately 71%","Both controls have identical ROSI values","ROSI cannot be calculated with the information given"],"answer":0,"explain":"<strong>Control B, with a ROSI of approximately 71% versus Control A's ROSI of 50%</strong> — Control A: (($80,000-$50,000)-$20,000)/$20,000 = $10,000/$20,000 = 50%. Control B: (($80,000-$20,000)-$35,000)/$35,000 = $25,000/$35,000 ≈ 71%. Control B delivers both a greater absolute risk reduction and a higher percentage return on the investment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Control A, with a ROSI of 50% versus Control B's ROSI of approximately 71%</b>: this correctly states both figures but incorrectly identifies Control A, the lower-ROSI option, as the better investment.</span><span class='qd'><b>Both controls have identical ROSI values</b>: the two controls have different costs and different risk reductions, producing different ROSI percentages.</span><span class='qd'><b>ROSI cannot be calculated with the information given</b>: sufficient information (ALE before, ALE after, and cost of control) is provided to calculate ROSI for both controls.</span>"},
{"id":"D2-063","domain":2,"obj":"2A3","diff":"hard","q":"A risk analysis technique that uses probability distributions and repeated random sampling to model a range of possible loss outcomes is known as:","options":["Delphi technique","SWOT analysis","Root cause analysis","Monte Carlo simulation"],"answer":3,"explain":"<strong>Monte Carlo simulation</strong> — this quantitative technique uses probability distributions and repeated random sampling to model a wide range of possible outcomes, providing a distribution of potential losses rather than a single point estimate.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delphi technique</b>: is an expert-consensus method, not a statistical simulation approach.</span><span class='qd'><b>SWOT analysis</b>: examines strengths, weaknesses, opportunities, and threats at a strategic level, not a probabilistic loss model.</span><span class='qd'><b>Root cause analysis</b>: is used to determine the underlying cause of an incident after the fact, not to model probabilistic future losses.</span>"},
{"id":"D2-064","domain":2,"obj":"2B3","diff":"med","q":"A company decides to discontinue accepting a rarely used, high-risk legacy payment method entirely because the cost of securing it exceeds its business value. This decision exemplifies which risk treatment?","options":["Risk avoidance","Risk mitigation","Risk transfer","Risk acceptance"],"answer":0,"explain":"<strong>Risk avoidance</strong> — discontinuing the activity itself (accepting the legacy payment method) removes the organization's exposure to the associated risk entirely, which is the defining feature of avoidance.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Risk mitigation</b>: would involve continuing to accept the payment method while adding controls to reduce risk, not discontinuing it.</span><span class='qd'><b>Risk transfer</b>: would involve shifting the risk to a third party while still offering the payment method, which is not what occurred.</span><span class='qd'><b>Risk acceptance</b>: would mean continuing to offer the method and tolerating the risk, the opposite of discontinuing it.</span>"},
{"id":"D2-065","domain":2,"obj":"2B3","diff":"easy","q":"A risk owner is presented with four options to treat a $200,000 ALE risk: (1) accept as-is, (2) a $40,000 control reducing ALE to $60,000, (3) full outsourcing that transfers the activity and its risk for a $150,000 annual fee, (4) discontinuing the risky activity entirely at a $500,000 opportunity cost in lost revenue. Which option is generally the MOST cost-effective treatment based on the figures given?","options":["Option 1, accept as-is","Option 2, the $40,000 control reducing ALE to $60,000","Option 3, outsourcing for $150,000","Option 4, discontinuing the activity at $500,000 opportunity cost"],"answer":1,"explain":"<strong>Option 2, the $40,000 control reducing ALE to $60,000</strong> — this option costs $40,000 and reduces the ALE by $140,000, yielding a strong net benefit (ROSI of 250%), clearly outperforming the other options on a cost-effectiveness basis: outsourcing costs $150,000 versus a $200,000 exposure (thin margin), and avoidance costs $500,000, far exceeding the risk itself.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Option 1, accept as-is</b>: retains the full $200,000 ALE with no reduction, which is worse than the net position achieved by the $40,000 control.</span><span class='qd'><b>Option 3, outsourcing for $150,000</b>: costs nearly as much as the original exposure itself, offering a much weaker return than the mitigation option.</span><span class='qd'><b>Option 4, discontinuing the activity at $500,000 opportunity cost</b>: this option costs far more than the risk it eliminates, making it economically unjustified here.</span>"},
{"id":"D2-066","domain":2,"obj":"2A4","diff":"hard","q":"Which group is typically responsible for formally approving the organization's overall risk appetite statement?","options":["The help desk team","The board of directors or equivalent senior governing body","Front-line employees","The building facilities manager"],"answer":1,"explain":"<strong>The board of directors or equivalent senior governing body</strong> — risk appetite is a strategic statement that reflects the organization's overall willingness to pursue risk, and its approval rests with the highest level of governance, typically the board.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The help desk team</b>: operates at a tactical support level with no authority over strategic risk decisions.</span><span class='qd'><b>Front-line employees</b>: execute day-to-day operations but do not set or approve enterprise-level risk appetite.</span><span class='qd'><b>The building facilities manager</b>: manages physical facilities, unrelated to enterprise risk governance authority.</span>"},
{"id":"D2-067","domain":2,"obj":"2A2","diff":"med","q":"An information security manager is documenting RACI (Responsible, Accountable, Consulted, Informed) roles for a risk treatment initiative. Which role should typically be marked 'Accountable' for the risk itself?","options":["The information security manager, in all cases","The project manager coordinating the technical implementation","The designated risk owner","The vendor providing the control technology"],"answer":2,"explain":"<strong>The designated risk owner</strong> — accountability for a risk's outcome belongs to its owner, consistent with the principle that risk ownership carries ultimate accountability, regardless of who performs supporting or consulting roles.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The information security manager, in all cases</b>: the security manager often facilitates and advises but is not automatically accountable for every business risk.</span><span class='qd'><b>The project manager coordinating the technical implementation</b>: the project manager is typically responsible for delivery tasks, not accountable for the risk itself.</span><span class='qd'><b>The vendor providing the control technology</b>: a vendor supplies a product or service but holds no accountability for the organization's risk.</span>"},
{"id":"D2-068","domain":2,"obj":"2B1","diff":"easy","q":"Which pairing BEST distinguishes a key performance indicator (KPI) from a key risk indicator (KRI)?","options":["A KPI and a KRI are always the exact same metric with different names","A KPI is always financial, while a KRI is always non-financial","A KPI measures how well an objective is being achieved, while a KRI signals the potential for future risk events affecting that objective","A KRI measures past performance only, while a KPI predicts future risk"],"answer":2,"explain":"<strong>A KPI measures how well an objective is being achieved, while a KRI signals the potential for future risk events affecting that objective</strong> — KPIs track progress toward goals and performance, whereas KRIs are forward-looking signals of increasing risk that could jeopardize those goals; the two are complementary but distinct.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A KPI and a KRI are always the exact same metric with different names</b>: while some metrics can serve both purposes, they measure fundamentally different things (performance versus risk exposure).</span><span class='qd'><b>A KPI is always financial, while a KRI is always non-financial</b>: both KPIs and KRIs can be financial or non-financial depending on context.</span><span class='qd'><b>A KRI measures past performance only, while a KPI predicts future risk</b>: this reverses the actual forward-looking nature of KRIs and backward-looking nature typical of many KPIs.</span>"},
{"id":"D2-069","domain":2,"obj":"2B4","diff":"med","q":"An organization wants to classify its third-party vendors to prioritize risk assessment effort. Which criterion is MOST appropriate for determining a vendor's risk tier?","options":["The alphabetical order of the vendor's company name","The length of time the vendor has existed as a company","The sensitivity of data accessed and the criticality of services the vendor provides to the organization","The vendor's total number of employees worldwide"],"answer":2,"explain":"<strong>The sensitivity of data accessed and the criticality of services the vendor provides to the organization</strong> — tiering vendors by data sensitivity and service criticality ensures that assessment effort and scrutiny are proportional to the actual risk each vendor poses to the organization.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The alphabetical order of the vendor's company name</b>: is an arbitrary criterion with no relationship to actual risk.</span><span class='qd'><b>The length of time the vendor has existed as a company</b>: longevity alone does not indicate the sensitivity of data or criticality of services provided.</span><span class='qd'><b>The vendor's total number of employees worldwide</b>: company size does not directly correlate with the risk posed to this specific organization.</span>"},
{"id":"D2-070","domain":2,"obj":"2B5","diff":"hard","q":"An organization calculates that the inherent risk of a data center outage is $1,000,000 in potential annual loss, and after implementing redundant power and generators, the residual risk drops to $150,000. Which figure represents the risk reduction achieved specifically by the implemented controls?","options":["$850,000","$1,000,000","$150,000","$1,150,000"],"answer":0,"explain":"<strong>$850,000</strong> — risk reduction = inherent risk - residual risk = $1,000,000 - $150,000 = $850,000, representing the value of exposure eliminated by the controls.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>$1,000,000</b>: this is the inherent risk before controls, not the reduction achieved.</span><span class='qd'><b>$150,000</b>: this is the residual risk remaining after controls, not the amount reduced.</span><span class='qd'><b>$1,150,000</b>: results from incorrectly adding the two figures rather than subtracting.</span>"},
{"id":"D2-071","domain":2,"obj":"2A5","diff":"med","q":"A CISO wants to demonstrate to the enterprise risk committee that information security risk management adds value beyond compliance. Which approach BEST achieves this?","options":["Presenting only the number of policies published during the year","Avoiding any mention of security risk in enterprise-level meetings","Linking security risk metrics and treatment decisions directly to business objectives, financial impact, and strategic initiatives supported by the ERM framework","Focusing exclusively on the number of vulnerabilities patched, without business context"],"answer":2,"explain":"<strong>Linking security risk metrics and treatment decisions directly to business objectives, financial impact, and strategic initiatives supported by the ERM framework</strong> — demonstrating value requires connecting security risk work to tangible business outcomes and strategic priorities, using the shared language and framework of ERM rather than isolated technical metrics.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Presenting only the number of policies published during the year</b>: policy counts do not demonstrate business value or risk impact.</span><span class='qd'><b>Avoiding any mention of security risk in enterprise-level meetings</b>: avoiding visibility undermines rather than demonstrates the value of the security risk function.</span><span class='qd'><b>Focusing exclusively on the number of vulnerabilities patched, without business context</b>: a raw technical count without business framing fails to convey strategic value to the committee.</span>"},
{"id":"D2-072","domain":2,"obj":"2A1","diff":"easy","q":"Which of the following is the BEST source for identifying emerging threats relevant to an organization's specific industry and technology stack?","options":["Threat intelligence feeds and information sharing groups relevant to the organization's sector and technologies","General news headlines about unrelated industries","The organization's five-year-old asset inventory with no updates","A single employee's personal opinion on likely future threats"],"answer":0,"explain":"<strong>Threat intelligence feeds and information sharing groups relevant to the organization's sector and technologies</strong> — sector-specific threat intelligence and information sharing and analysis centers (ISACs) provide timely, relevant insight into emerging threats that directly affect the organization's environment.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>General news headlines about unrelated industries</b>: broad, unrelated news lacks the specificity needed to identify relevant emerging threats.</span><span class='qd'><b>The organization's five-year-old asset inventory with no updates</b>: an outdated inventory does not reflect current systems or emerging threats.</span><span class='qd'><b>A single employee's personal opinion on likely future threats</b>: an individual opinion lacks the rigor and breadth of structured threat intelligence sources.</span>"},
{"id":"D2-073","domain":2,"obj":"2B6","diff":"med","q":"An organization's risk management framework requires that all high and critical risks be reviewed quarterly, while low risks are reviewed annually. This differentiated review frequency is BEST justified by which principle?","options":["All risks should always be reviewed with identical frequency regardless of severity","Review frequency should be determined randomly to avoid bias","Only risks owned by the CEO should ever be reviewed","Review frequency should be risk-based, allocating more frequent oversight to higher-severity risks that could cause greater harm if conditions change"],"answer":3,"explain":"<strong>Review frequency should be risk-based, allocating more frequent oversight to higher-severity risks that could cause greater harm if conditions change</strong> — a risk-based review cadence focuses limited oversight resources on the risks that pose the greatest potential harm, ensuring timely detection of changes that matter most.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>All risks should always be reviewed with identical frequency regardless of severity</b>: uniform frequency wastes resources on low-severity risks while potentially under-reviewing high-severity ones.</span><span class='qd'><b>Review frequency should be determined randomly to avoid bias</b>: randomness undermines the ability to systematically prioritize oversight based on actual risk severity.</span><span class='qd'><b>Only risks owned by the CEO should ever be reviewed</b>: review cadence should be based on risk severity, not on who happens to own the risk.</span>"},
{"id":"D2-074","domain":2,"obj":"2A3","diff":"hard","q":"An information security manager needs to present risk analysis results to a board with limited technical background, focusing on relative prioritization rather than precise dollar figures. Which output format is MOST appropriate?","options":["A raw database export of vulnerability scan results","A detailed Monte Carlo simulation output with statistical distributions","Full source code of the affected applications","A qualitative risk heat map showing likelihood versus impact for top risks"],"answer":3,"explain":"<strong>A qualitative risk heat map showing likelihood versus impact for top risks</strong> — a heat map presents relative risk prioritization visually and simply, which is well suited to a non-technical board audience focused on prioritization rather than precise figures.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A raw database export of vulnerability scan results</b>: raw technical data is not digestible or meaningful for a non-technical board audience.</span><span class='qd'><b>A detailed Monte Carlo simulation output with statistical distributions</b>: highly technical statistical output would likely overwhelm a board seeking simple prioritization insight.</span><span class='qd'><b>Full source code of the affected applications</b>: source code is entirely inappropriate and meaningless for board-level risk communication.</span>"},
{"id":"D2-075","domain":2,"obj":"2B2","diff":"easy","q":"If the annualized loss expectancy (ALE) for a risk is $60,000 and the organization spends exactly $60,000 per year on a control that fully eliminates the risk, what does this indicate about the investment from a pure cost-benefit perspective?","options":["It is clearly a highly favorable investment with strong positive ROSI","It always represents a loss-making investment regardless of other factors","ROSI is undefined in this scenario","The investment breaks even, with a ROSI of approximately 0%, since the cost equals the avoided loss"],"answer":3,"explain":"<strong>The investment breaks even, with a ROSI of approximately 0%, since the cost equals the avoided loss</strong> — ROSI = (Risk reduction - Cost of control) / Cost of control = ($60,000 - $60,000) / $60,000 = 0%, meaning the control costs exactly as much as the risk it eliminates, a breakeven position rather than a net financial gain.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It is clearly a highly favorable investment with strong positive ROSI</b>: a 0% ROSI is a breakeven result, not a strongly favorable one.</span><span class='qd'><b>It always represents a loss-making investment regardless of other factors</b>: breaking even is not the same as a loss; non-financial factors could still justify the spend even at 0% ROSI.</span><span class='qd'><b>ROSI is undefined in this scenario</b>: ROSI is calculable here and simply equals zero, not undefined.</span>"},
{"id":"D2-076","domain":2,"obj":"2A2","diff":"med","q":"A risk owner delegates day-to-day monitoring of a specific control to an IT operations manager but retains ultimate accountability for the risk. This arrangement is BEST described as:","options":["An invalid arrangement since accountability cannot be separated from daily tasks","A transfer of all accountability to the IT operations manager","A valid delegation of operational responsibility for the control while the risk owner retains accountability for the risk outcome","Evidence that the risk register should be closed"],"answer":2,"explain":"<strong>A valid delegation of operational responsibility for the control while the risk owner retains accountability for the risk outcome</strong> — responsibility for day-to-day control operation can be delegated to a control owner or operational team, but ultimate accountability for the risk itself remains with the designated risk owner.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>An invalid arrangement since accountability cannot be separated from daily tasks</b>: delegating operational tasks while retaining accountability is a standard and valid governance practice.</span><span class='qd'><b>A transfer of all accountability to the IT operations manager</b>: delegation of tasks does not equate to a full transfer of accountability for the risk.</span><span class='qd'><b>Evidence that the risk register should be closed</b>: delegating monitoring responsibilities has no bearing on whether the risk entry should be closed.</span>"},
{"id":"D2-077","domain":2,"obj":"2B3","diff":"med","q":"Which of the following BEST illustrates a hybrid risk treatment approach combining both mitigation and transfer?","options":["Purchasing insurance alone with no internal controls implemented","Discontinuing the data processing activity entirely","Accepting the risk without any action","Implementing encryption and access controls on sensitive data while also purchasing cyber-insurance to cover residual breach costs"],"answer":3,"explain":"<strong>Implementing encryption and access controls on sensitive data while also purchasing cyber-insurance to cover residual breach costs</strong> — this combines mitigation (reducing likelihood/impact through technical controls) with transfer (shifting remaining financial impact to an insurer), a common and effective hybrid treatment strategy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Purchasing insurance alone with no internal controls implemented</b>: this is pure transfer without any mitigation component, not a hybrid approach.</span><span class='qd'><b>Discontinuing the data processing activity entirely</b>: this is pure avoidance, not a combination of mitigation and transfer.</span><span class='qd'><b>Accepting the risk without any action</b>: this is pure acceptance and involves no active treatment at all.</span>"},
{"id":"D2-078","domain":2,"obj":"2A4","diff":"hard","q":"A financial services firm sets a strict risk tolerance around uptime for its trading platform because even a few minutes of downtime can cause substantial financial and reputational harm. This scenario BEST illustrates that risk tolerance thresholds should be:","options":["Identical across all systems within the organization regardless of criticality","Determined solely by IT infrastructure cost, not business impact","Set independently based on the specific consequences and criticality associated with each system or process","Ignored in favor of a single blanket enterprise policy for all systems"],"answer":2,"explain":"<strong>Set independently based on the specific consequences and criticality associated with each system or process</strong> — tolerance thresholds should reflect the actual consequences of deviation for that specific system; a trading platform with severe downtime consequences warrants a stricter threshold than a less critical system.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Identical across all systems within the organization regardless of criticality</b>: uniform thresholds ignore the differing consequences and criticality of different systems.</span><span class='qd'><b>Determined solely by IT infrastructure cost, not business impact</b>: tolerance should be driven primarily by business impact and consequence, not merely infrastructure cost.</span><span class='qd'><b>Ignored in favor of a single blanket enterprise policy for all systems</b>: a single blanket policy would fail to reflect the varying criticality of different systems and processes.</span>"},
{"id":"D2-079","domain":2,"obj":"2B1","diff":"easy","q":"An information security manager proposes 'number of security awareness training completions' as a KRI for phishing susceptibility risk. A peer argues this is a weak indicator. What is the MOST valid basis for that criticism?","options":["Training completion counts are too expensive to track","Training completions should never be measured under any circumstances","Training completion measures participation, not actual behavior change or reduced susceptibility, making it a weak leading indicator of the specific risk","The metric is a perfect and sufficient KRI as originally proposed"],"answer":2,"explain":"<strong>Training completion measures participation, not actual behavior change or reduced susceptibility, making it a weak leading indicator of the specific risk</strong> — completing training does not guarantee reduced susceptibility to phishing; a more direct KRI, such as phishing simulation click-through or reporting rates, better reflects actual behavioral risk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Training completion counts are too expensive to track</b>: cost of tracking is not the core issue; the relevance of the metric to actual risk behavior is the concern.</span><span class='qd'><b>Training completions should never be measured under any circumstances</b>: the metric can still be useful as a KPI for program compliance, just not as a strong KRI for susceptibility.</span><span class='qd'><b>The metric is a perfect and sufficient KRI as originally proposed</b>: this contradicts the valid criticism that participation does not equal behavior change.</span>"},
{"id":"D2-080","domain":2,"obj":"2B4","diff":"med","q":"Which contractual clause is MOST directly useful for enabling an organization to verify a critical vendor's ongoing security control effectiveness?","options":["A right-to-audit clause allowing the organization or an independent party to assess the vendor's controls","A marketing exclusivity clause","A most-favored-customer pricing clause","An automatic renewal clause with no review provisions"],"answer":0,"explain":"<strong>A right-to-audit clause allowing the organization or an independent party to assess the vendor's controls</strong> — this clause gives the organization contractual authority to verify the vendor's actual security control effectiveness, rather than relying solely on vendor self-attestation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A marketing exclusivity clause</b>: relates to commercial exclusivity, not security assurance.</span><span class='qd'><b>A most-favored-customer pricing clause</b>: relates to pricing terms, unrelated to verifying security controls.</span><span class='qd'><b>An automatic renewal clause with no review provisions</b>: automatically renewing without review provisions would actually reduce oversight opportunities, not increase them.</span>"},
{"id":"D2-081","domain":2,"obj":"2A1","diff":"easy","q":"Which of the following BEST describes the relationship between asset valuation and risk analysis?","options":["Accurate asset valuation is a foundational input that helps determine potential impact and prioritize which risks warrant the most attention and investment","Asset valuation is irrelevant to risk analysis and can be skipped entirely","Asset valuation only matters for physical assets, never for data or intangible assets","Asset valuation should always use the original purchase price regardless of current business value"],"answer":0,"explain":"<strong>Accurate asset valuation is a foundational input that helps determine potential impact and prioritize which risks warrant the most attention and investment</strong> — understanding what an asset is worth to the business (including replacement, reputational, and operational value) directly informs the impact side of risk analysis and helps prioritize resources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Asset valuation is irrelevant to risk analysis and can be skipped entirely</b>: valuation is a core input to calculating potential impact and cannot be meaningfully skipped.</span><span class='qd'><b>Asset valuation only matters for physical assets, never for data or intangible assets</b>: data and intangible assets, such as intellectual property or reputation, often carry substantial value that must also be assessed.</span><span class='qd'><b>Asset valuation should always use the original purchase price regardless of current business value</b>: original purchase price often does not reflect current replacement cost or business value, especially for data and intangible assets.</span>"},
{"id":"D2-082","domain":2,"obj":"2B2","diff":"med","q":"An organization determines that a particular risk has an SLE of $15,000 and occurs on average three times per year. What is the ALE?","options":["$5,000","$45,000","$15,000","$180,000"],"answer":1,"explain":"<strong>$45,000</strong> — ALE = SLE x ARO = $15,000 x 3 = $45,000, since an ARO greater than 1 simply reflects a threat expected to occur more than once per year.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>$5,000</b>: results from dividing SLE by 3 rather than multiplying.</span><span class='qd'><b>$15,000</b>: this is the SLE only, without factoring in the frequency of three occurrences per year.</span><span class='qd'><b>$180,000</b>: does not correspond to the correct multiplication of the given SLE and ARO.</span>"},
{"id":"D2-083","domain":2,"obj":"2A3","diff":"hard","q":"An organization wants to combine the speed of qualitative assessment with some numerical rigor for board reporting, without the cost of a full quantitative study. Which analysis approach BEST fits this need?","options":["Purely qualitative analysis with no numeric elements","Full Monte Carlo simulation with statistical distributions","Semi-quantitative analysis using weighted numeric scores for likelihood and impact categories","Ignoring risk analysis and relying only on compliance checklists"],"answer":2,"explain":"<strong>Semi-quantitative analysis using weighted numeric scores for likelihood and impact categories</strong> — this approach provides more rigor and comparability than purely descriptive ratings while avoiding the time and data demands of full quantitative modeling, making it well suited to this need.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Purely qualitative analysis with no numeric elements</b>: lacks the numerical rigor the organization is seeking for board reporting.</span><span class='qd'><b>Full Monte Carlo simulation with statistical distributions</b>: is more costly and data-intensive than what is being requested.</span><span class='qd'><b>Ignoring risk analysis and relying only on compliance checklists</b>: checklists do not provide risk analysis or prioritization at all.</span>"},
{"id":"D2-084","domain":2,"obj":"2B5","diff":"med","q":"A newly identified risk has an inherent risk rating of 'critical.' After reviewing existing controls, the information security manager determines the residual risk rating is 'low.' What should happen NEXT in the risk management process?","options":["Validate that the existing controls are actually operating effectively before finalizing the low residual rating, then present it for the risk owner's review","Immediately remove the risk from the register since it is now rated low","Escalate the risk as critical to the board regardless of the residual rating","Ignore the finding since inherent risk ratings are the only ones that matter"],"answer":0,"explain":"<strong>Validate that the existing controls are actually operating effectively before finalizing the low residual rating, then present it for the risk owner's review</strong> — before accepting a large drop from critical to low, it is essential to verify that the relied-upon controls are genuinely operating effectively, then formally present the validated residual rating to the risk owner for review and decision.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Immediately remove the risk from the register since it is now rated low</b>: risks should remain tracked and periodically reviewed even at a low residual rating, not removed outright.</span><span class='qd'><b>Escalate the risk as critical to the board regardless of the residual rating</b>: escalating at the inherent level while ignoring validated control effectiveness misrepresents the actual current exposure.</span><span class='qd'><b>Ignore the finding since inherent risk ratings are the only ones that matter</b>: residual risk, which reflects the effect of actual controls, is what matters most for ongoing decision-making.</span>"},
{"id":"D2-085","domain":2,"obj":"2B6","diff":"easy","q":"Which of the following is the BEST reason to involve business process owners, not just IT staff, in periodic risk reassessment activities?","options":["Business process owners have no useful perspective on risk","Business process owners understand the current operational context, priorities, and impact tolerance of the processes they run, which is essential to accurate reassessment","Only IT staff can understand technical vulnerabilities relevant to reassessment","Involving business owners slows down the process with no added value"],"answer":1,"explain":"<strong>Business process owners understand the current operational context, priorities, and impact tolerance of the processes they run, which is essential to accurate reassessment</strong> — business owners bring critical insight into how a process is actually used today, its current importance, and the real-world impact of disruption, which technical staff alone may not fully capture.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Business process owners have no useful perspective on risk</b>: this understates the essential operational and business-impact insight they provide.</span><span class='qd'><b>Only IT staff can understand technical vulnerabilities relevant to reassessment</b>: while IT staff are essential for technical vulnerability insight, business context from process owners is equally necessary for a complete reassessment.</span><span class='qd'><b>Involving business owners slows down the process with no added value</b>: their involvement adds essential business context, which is a valuable input, not merely a delay.</span>"},
{"id":"D2-086","domain":2,"obj":"2A5","diff":"hard","q":"Which of the following would MOST likely indicate that information security risk management is operating in a silo, disconnected from enterprise risk management?","options":["Information security risks appear on the same enterprise risk dashboard reviewed by the risk committee","The CISO regularly attends enterprise risk committee meetings","Security risk appetite is derived directly from the board-approved enterprise risk appetite","Security risk decisions are made and communicated using terminology and thresholds inconsistent with the rest of the organization's ERM framework"],"answer":3,"explain":"<strong>Security risk decisions are made and communicated using terminology and thresholds inconsistent with the rest of the organization's ERM framework</strong> — inconsistent terminology and thresholds prevent security risk from being meaningfully compared or integrated with other enterprise risks, a clear sign of a disconnected, siloed approach.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Information security risks appear on the same enterprise risk dashboard reviewed by the risk committee</b>: shared dashboard visibility is a sign of integration, not disconnection.</span><span class='qd'><b>The CISO regularly attends enterprise risk committee meetings</b>: active CISO participation in ERM governance reflects integration, not a silo.</span><span class='qd'><b>Security risk appetite is derived directly from the board-approved enterprise risk appetite</b>: deriving security appetite from the enterprise-level statement is a strong indicator of proper alignment and integration.</span>"},
{"id":"D2-087","domain":2,"obj":"2A1","diff":"med","q":"A risk assessment identifies a threat-vulnerability pairing with high likelihood but the affected asset has negligible business value. How should this be reflected in the risk analysis?","options":["The risk should automatically be rated critical because likelihood is high, regardless of asset value","Asset value should be ignored entirely in favor of likelihood alone","The risk should be removed from the register immediately without documentation","The overall risk rating should account for both likelihood and impact, and low asset value/impact should result in a correspondingly lower overall risk rating despite high likelihood"],"answer":3,"explain":"<strong>The overall risk rating should account for both likelihood and impact, and low asset value/impact should result in a correspondingly lower overall risk rating despite high likelihood</strong> — risk is a function of both likelihood and impact; a high-likelihood event against a low-value asset still yields a lower overall risk rating because the potential impact is minimal.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The risk should automatically be rated critical because likelihood is high, regardless of asset value</b>: rating based on likelihood alone ignores the impact dimension that is equally essential to risk analysis.</span><span class='qd'><b>Asset value should be ignored entirely in favor of likelihood alone</b>: ignoring impact/asset value produces an incomplete and potentially misleading risk rating.</span><span class='qd'><b>The risk should be removed from the register immediately without documentation</b>: even low-rated risks should typically remain documented and tracked, not silently removed.</span>"},
{"id":"D2-088","domain":2,"obj":"2B3","diff":"easy","q":"Which factor should MOST influence the choice between mitigating a risk versus transferring it via insurance?","options":["The personal preference of a single IT technician","The insurance broker's recommendation alone, without further analysis","A comparison of the cost and effectiveness of available controls against the cost and coverage limitations of available insurance, relative to the risk owner's objectives","Whichever option requires the least paperwork to implement"],"answer":2,"explain":"<strong>A comparison of the cost and effectiveness of available controls against the cost and coverage limitations of available insurance, relative to the risk owner's objectives</strong> — choosing between mitigation and transfer should be a deliberate cost-benefit and suitability comparison, weighing control effectiveness and cost against insurance cost, coverage limits, and exclusions, aligned to the risk owner's objectives.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The personal preference of a single IT technician</b>: an individual technician's preference lacks the business and financial analysis needed for this decision.</span><span class='qd'><b>The insurance broker's recommendation alone, without further analysis</b>: relying solely on a broker, who has a vested interest in selling insurance, without independent analysis is not sound risk decision-making.</span><span class='qd'><b>Whichever option requires the least paperwork to implement</b>: administrative convenience should not drive a substantive risk treatment decision.</span>"},
{"id":"D2-089","domain":2,"obj":"2A4","diff":"med","q":"An organization's documented risk acceptance criteria specify that only risks below a defined ALE threshold can be accepted without executive sign-off. A department wants to accept a risk with an ALE well above that threshold. What should occur?","options":["The risk must be escalated for executive sign-off in accordance with the documented acceptance criteria before being accepted","The department can proceed with acceptance on its own since it is the risk owner","The threshold should be silently ignored for this one case to save time","The risk should be automatically transferred to insurance instead"],"answer":0,"explain":"<strong>The risk must be escalated for executive sign-off in accordance with the documented acceptance criteria before being accepted</strong> — documented acceptance criteria exist precisely to ensure risks above a certain threshold receive appropriate senior-level scrutiny and approval before being accepted; the department should follow this defined escalation path.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The department can proceed with acceptance on its own since it is the risk owner</b>: risk ownership does not override documented governance requirements for acceptance above a defined threshold.</span><span class='qd'><b>The threshold should be silently ignored for this one case to save time</b>: bypassing defined governance controls undermines the integrity of the risk acceptance process.</span><span class='qd'><b>The risk should be automatically transferred to insurance instead</b>: the criteria call for executive escalation, not a specific treatment choice like automatic transfer.</span>"},
{"id":"D2-090","domain":2,"obj":"2B1","diff":"hard","q":"A security dashboard reports dozens of raw technical metrics (e.g., firewall rule count, patch counts, ticket volume) directly to the executive risk committee without context or thresholds. What is the MOST significant weakness of this reporting approach as a KRI program?","options":["There are too few metrics being reported to the committee","Raw technical metrics without defined thresholds, trends, or business context do not clearly signal changing risk levels or trigger action, reducing their value as KRIs","The dashboard should include even more raw technical data with no added context","Executives should be trained to interpret raw firewall rule counts instead of receiving synthesized indicators"],"answer":1,"explain":"<strong>Raw technical metrics without defined thresholds, trends, or business context do not clearly signal changing risk levels or trigger action, reducing their value as KRIs</strong> — effective KRIs need defined thresholds, trend context, and clear linkage to specific risks so that executives can recognize when action is needed; a flood of uncontextualized raw metrics fails to serve this purpose.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>There are too few metrics being reported to the committee</b>: the problem described is a lack of context and thresholds, not an insufficient quantity of metrics.</span><span class='qd'><b>The dashboard should include even more raw technical data with no added context</b>: adding more uncontextualized data would worsen, not solve, the core problem.</span><span class='qd'><b>Executives should be trained to interpret raw firewall rule counts instead of receiving synthesized indicators</b>: the responsibility lies with translating technical data into meaningful risk indicators, not training executives to interpret raw technical output themselves.</span>"},
{"id":"D2-091","domain":2,"obj":"2B2","diff":"med","q":"A control eliminates a risk entirely (100% reduction) at an annual cost of $25,000, and the prior ALE for that risk was $25,000. What is the ROSI?","options":["0%","100%","25%","-100%"],"answer":0,"explain":"<strong>0%</strong> — ROSI = (Risk reduction - Cost of control) / Cost of control = ($25,000 - $25,000) / $25,000 = 0%, meaning the cost of full elimination exactly equals the value of the loss avoided, a breakeven outcome.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>100%</b>: would only occur if the risk reduction were double the cost of the control, which is not the case here.</span><span class='qd'><b>25%</b>: does not correspond to the correct formula applied to these equal figures.</span><span class='qd'><b>-100%</b>: would imply the cost of control provided no risk reduction at all, which contradicts the given full elimination.</span>"},
{"id":"D2-092","domain":2,"obj":"2A2","diff":"easy","q":"Two departments both claim ownership of the same risk related to a shared customer database, leading to confusion about who should approve treatment decisions. What is the information security manager's BEST recommendation?","options":["Facilitate a discussion with both departments and governance to designate a single accountable risk owner based on primary authority over the asset","Allow both departments to continue claiming joint ownership indefinitely","Assign ownership randomly by drawing lots","Remove the risk from the register to avoid the conflict"],"answer":0,"explain":"<strong>Facilitate a discussion with both departments and governance to designate a single accountable risk owner based on primary authority over the asset</strong> — resolving ownership ambiguity requires a facilitated discussion, informed by governance, to assign a single accountable owner (typically the party with primary authority over the shared asset), avoiding the accountability gaps that dual ownership creates.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Allow both departments to continue claiming joint ownership indefinitely</b>: unresolved dual ownership perpetuates confusion and slows decision-making.</span><span class='qd'><b>Assign ownership randomly by drawing lots</b>: an arbitrary method ignores the actual authority and accountability structure needed for effective ownership.</span><span class='qd'><b>Remove the risk from the register to avoid the conflict</b>: removing a valid, still-existing risk to sidestep an ownership disagreement leaves the organization blind to real exposure.</span>"},
{"id":"D2-093","domain":2,"obj":"2A3","diff":"med","q":"Which of the following is a common criticism of purely quantitative risk analysis?","options":["It never produces numeric results","It cannot be used to support cost-benefit decisions","It can create a false sense of precision when underlying data, assumptions, or probability estimates are unreliable","It is always faster to perform than qualitative analysis"],"answer":2,"explain":"<strong>It can create a false sense of precision when underlying data, assumptions, or probability estimates are unreliable</strong> — quantitative outputs look precise, but if the underlying loss and probability data are weak or speculative, the resulting figures can mislead decision-makers into overconfidence.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It never produces numeric results</b>: quantitative analysis specifically does produce numeric results; that is its defining characteristic.</span><span class='qd'><b>It cannot be used to support cost-benefit decisions</b>: quantitative analysis is particularly well suited to cost-benefit decisions such as ROSI calculations.</span><span class='qd'><b>It is always faster to perform than qualitative analysis</b>: quantitative analysis is generally more time- and data-intensive, not faster, than qualitative analysis.</span>"},
{"id":"D2-094","domain":2,"obj":"2B3","diff":"hard","q":"An organization decides to accept a moderate risk because the cost of any available treatment option significantly exceeds the potential loss from the risk itself. This decision is BEST justified by which principle?","options":["Risk treatment decisions should be cost-effective, avoiding spending more on a control than the value of the risk it addresses","Controls should always be implemented regardless of cost","Risk acceptance is never an appropriate treatment option","Only risk transfer is acceptable when treatment costs are high"],"answer":0,"explain":"<strong>Risk treatment decisions should be cost-effective, avoiding spending more on a control than the value of the risk it addresses</strong> — a fundamental principle of risk management is that treatment costs should be proportionate to the risk; when all treatment options cost more than the risk itself, informed acceptance can be the most rational, cost-effective decision.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Controls should always be implemented regardless of cost</b>: this ignores the fundamental cost-benefit principle underlying sound risk treatment decisions.</span><span class='qd'><b>Risk acceptance is never an appropriate treatment option</b>: acceptance is a legitimate and sometimes optimal treatment choice, particularly in cases like this one.</span><span class='qd'><b>Only risk transfer is acceptable when treatment costs are high</b>: transfer is one option among several and is not automatically the correct choice simply because mitigation costs are high.</span>"},
{"id":"D2-095","domain":2,"obj":"2B4","diff":"easy","q":"A multinational organization onboards a new vendor that will store data in a jurisdiction with materially weaker data protection laws than the organization's home country. Which risk consideration is MOST important to address before finalizing the engagement?","options":["The vendor's office decor and physical branding","Cross-border data transfer and jurisdictional legal/regulatory risk, including applicable data protection and sovereignty requirements","The vendor's preferred programming language for internal tools","The number of social media followers the vendor has"],"answer":1,"explain":"<strong>Cross-border data transfer and jurisdictional legal/regulatory risk, including applicable data protection and sovereignty requirements</strong> — storing data in a jurisdiction with weaker protections raises significant legal, regulatory, and data sovereignty risks that must be assessed and addressed contractually or through additional safeguards before proceeding.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The vendor's office decor and physical branding</b>: is entirely irrelevant to the legal and regulatory risk of cross-border data handling.</span><span class='qd'><b>The vendor's preferred programming language for internal tools</b>: internal technology choices are not the primary concern relative to jurisdictional data protection risk.</span><span class='qd'><b>The number of social media followers the vendor has</b>: social media presence has no bearing on legal or regulatory risk exposure.</span>"},
{"id":"D2-096","domain":2,"obj":"2A5","diff":"med","q":"Which of the following BEST supports consistent risk aggregation when rolling up individual project-level risks into a single enterprise risk profile?","options":["Applying the same enterprise-approved risk taxonomy, criteria, and scoring methodology across all projects before aggregation","Allowing each project team to use its own undocumented risk scoring approach","Aggregating only risks that project teams consider important, with no standard criteria","Ignoring project-level risk entirely and only assessing risk at the enterprise level"],"answer":0,"explain":"<strong>Applying the same enterprise-approved risk taxonomy, criteria, and scoring methodology across all projects before aggregation</strong> — consistent aggregation requires that all project-level risks be assessed using the same standardized taxonomy and scoring approach, so they can be meaningfully combined into an accurate enterprise-wide risk profile.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Allowing each project team to use its own undocumented risk scoring approach</b>: inconsistent, undocumented approaches make meaningful aggregation impossible.</span><span class='qd'><b>Aggregating only risks that project teams consider important, with no standard criteria</b>: subjective, uncriteria-based selection risks omitting significant exposures from the enterprise view.</span><span class='qd'><b>Ignoring project-level risk entirely and only assessing risk at the enterprise level</b>: ignoring project-level detail would miss risks that originate at that level before they can roll up.</span>"},
{"id":"D2-097","domain":2,"obj":"2B6","diff":"med","q":"An organization's risk management policy requires that any risk treatment plan include a target completion date and an assigned owner for remediation tasks. What is the PRIMARY benefit of this requirement?","options":["It has no real benefit and only adds administrative burden","It guarantees that all risks will be fully eliminated","It replaces the need for periodic risk reassessment","It creates accountability and enables tracking of treatment progress, reducing the likelihood that identified risks remain untreated indefinitely"],"answer":3,"explain":"<strong>It creates accountability and enables tracking of treatment progress, reducing the likelihood that identified risks remain untreated indefinitely</strong> — assigning an owner and target date to each treatment plan ensures clear accountability and allows progress to be monitored, preventing risks from languishing without action.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>It has no real benefit and only adds administrative burden</b>: the accountability and tracking benefits are substantive, not merely administrative overhead.</span><span class='qd'><b>It guarantees that all risks will be fully eliminated</b>: having a target date and owner does not guarantee successful or complete risk elimination, only better tracking and accountability.</span><span class='qd'><b>It replaces the need for periodic risk reassessment</b>: tracking treatment plans is a complementary practice to, not a replacement for, ongoing periodic reassessment.</span>"},
{"id":"D2-098","domain":2,"obj":"2A1","diff":"hard","q":"An organization's risk assessment methodology fails to consider the potential for cascading impacts, where a failure in one system triggers failures in dependent systems. What is the MOST significant consequence of this gap?","options":["The methodology will run faster with less complexity, which is always beneficial","The organization may significantly underestimate the true business impact of certain risks, leading to under-resourced treatment","There is no meaningful consequence since cascading impacts are rare in practice","The gap only affects physical security risks, not information security risks"],"answer":1,"explain":"<strong>The organization may significantly underestimate the true business impact of certain risks, leading to under-resourced treatment</strong> — failing to account for cascading or dependency-driven impacts can cause the assessed impact of a risk to be understated, resulting in inadequate investment in treatment relative to the actual potential harm.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The methodology will run faster with less complexity, which is always beneficial</b>: sacrificing accuracy for speed is not a genuine benefit when it leads to materially understated risk.</span><span class='qd'><b>There is no meaningful consequence since cascading impacts are rare in practice</b>: cascading impacts, particularly in interconnected IT environments, are a well-recognized and significant risk consideration, not a rare edge case.</span><span class='qd'><b>The gap only affects physical security risks, not information security risks</b>: cascading impacts are highly relevant to information security, such as when a compromised system enables lateral movement to dependent systems.</span>"},
{"id":"D2-099","domain":2,"obj":"2B5","diff":"easy","q":"A risk owner accepts a risk with a documented residual ALE of $75,000 based on the assumption that a specific compensating control operates continuously. Six months later, that control is temporarily disabled for a system upgrade with no formal risk reassessment performed. What is the MOST accurate statement about the current risk status?","options":["The residual risk remains accurately reflected at $75,000 since the original acceptance is still technically on file","The inherent risk has decreased because of the system upgrade","No action is needed since the control will eventually be re-enabled","The actual current risk is likely understated in the register, since the compensating control the acceptance relied upon is not operating, effectively raising the real residual risk closer to the inherent level"],"answer":3,"explain":"<strong>The actual current risk is likely understated in the register, since the compensating control the acceptance relied upon is not operating, effectively raising the real residual risk closer to the inherent level</strong> — when a control that a risk acceptance depended on is disabled, the documented residual risk no longer reflects reality; the true current exposure is higher, and this change should trigger a reassessment and possibly a new acceptance decision or compensating measure.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The residual risk remains accurately reflected at $75,000 since the original acceptance is still technically on file</b>: a stale acceptance based on an assumption that no longer holds does not reflect the organization's actual current exposure.</span><span class='qd'><b>The inherent risk has decreased because of the system upgrade</b>: inherent risk is unaffected by control status changes; only residual risk changes when a relied-upon control is disabled.</span><span class='qd'><b>No action is needed since the control will eventually be re-enabled</b>: the temporary gap still represents real elevated exposure that should be assessed and, if needed, addressed with interim measures.</span>"},
{"id":"D2-100","domain":2,"obj":"2B1","diff":"med","q":"An organization wants to establish a small set of enterprise-wide key risk indicators for its information security program. Which approach is MOST likely to result in effective, actionable KRIs?","options":["Select indicators randomly from a generic industry list without regard to the organization's specific risk profile","Select as many indicators as possible to ensure nothing is missed, regardless of relevance","Select a focused set of indicators directly tied to the organization's top risks, with clearly defined thresholds and assigned owners for response","Select indicators based solely on what is easiest to automate, regardless of relevance to actual risk"],"answer":2,"explain":"<strong>Select a focused set of indicators directly tied to the organization's top risks, with clearly defined thresholds and assigned owners for response</strong> — effective KRI programs prioritize a manageable number of indicators that are clearly linked to the organization's most significant risks, each with defined thresholds and an owner accountable for responding when thresholds are breached.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Select indicators randomly from a generic industry list without regard to the organization's specific risk profile</b>: generic, unrelated indicators are unlikely to reflect the organization's actual risk profile or provide actionable insight.</span><span class='qd'><b>Select as many indicators as possible to ensure nothing is missed, regardless of relevance</b>: an excessive number of irrelevant indicators creates noise and dilutes attention from the metrics that truly matter.</span><span class='qd'><b>Select indicators based solely on what is easiest to automate, regardless of relevance to actual risk</b>: ease of automation should not override the fundamental requirement that a KRI be relevant to actual risk exposure.</span>"}
]);
